    ) AS nh
    ON link.{{ link_hashkey }} = nh.{{ link_hashkey }}
    
    WHEN MATCHED THEN
        UPDATE SET 
            {{ new_link_hashkey_name }} = nh.{{ new_link_hashkey_name }}
