                ON sat.{{ hashkey }} = parent.join_key
            WHERE sat.{{ rsrc_alias }} NOT IN ('{{ unknown_value_rsrc }}', '{{ error_value_rsrc }}')
        ),

        {# 3. Multi-Active HashDiff Prep (Grouped) #}
