    {% endfor %}

    WHEN MATCHED THEN
        UPDATE SET 
            {{ new_hashkey_name }} = nh.{{ new_hashkey_name }},
            {{ new_hashdiff_name }} = nh.{{ new_hashdiff_name }}

    {% endset %}

    {{ return(merge_sql) }}

{% endmacro %}

