                sat.{{ new_hashdiff_name | replace('_new', '') }} AS {{ new_hashdiff_name }}
            FROM {{ satellite_relation }} sat
            WHERE sat.{{ rsrc_alias }} IN ('{{ unknown_value_rsrc }}', '{{ error_value_rsrc }}') 
        ) nh
    WHERE nh.{{ ldts_col }} = {{ satellite_relation }}.{{ ldts_col }}
    AND nh.{{ hashkey }} = {{ satellite_relation }}.{{ hashkey }}

    {% endset %}

    {{ return(update_sql) }}

{% endmacro %}

macro.datavault4dbt.default__derived_col.macro_sql:
{%- macro default__derived_columns_datatypes(columns, source_relation) -%}

{%- set all_source_columns = adapter.get_columns_in_relation(source_relation) -%}

{%- if columns is not mapping and columns is string -%}
