            {%- do columns.update({column_name: {'datatype': datatype, 'value': value, 'col_size': col_size} }) -%}
        {%- endif -%}

    {%- endfor -%}

{%- endif -%}

{{ return(columns | tojson) }}

{%- endmacro -%}

