{# Creating Ghost Record for error case, based on datatype #}
error_values AS (

    SELECT

    {{ datavault4dbt.string_to_timestamp(timestamp_format , end_of_all_times) }} as {{ load_datetime_col_name }}
    ,'{{ error_value_rsrc }}' as {{ record_source_col_name }}

