{%- endif -%}

{{ return(timestamp_format) }}

{%- endmacro -%}

macro.datavault4dbt.control_snap_v0.macro_sql:
{%- macro control_snap_v0(yaml_metadata=none, start_date=none, daily_snapshot_time=none, sdts_alias=none, end_date=none) -%}


    {% set start_date_description = "
    start_date::timestamp           Defines the earliest timestamp that should be available inside the snapshot_table. The time part of this
                                    timestamp needs to be set to '00:00:00'. The format of this timestamp must equal to the timestamp format
                                    defined in the global variable 'datavault4dbt.timestamp_format'.

                                    Examples:
                                        '2015-01-01T00-00-00'   This snapshot table would hold daily snapshots beginning at 2015.    
    " %}

    {% set daily_snapshot_time_description = "
    daily_snapshot_time::time       Defines the time that your daily snapshots should have. Usually this is either something right before
                                    daily business starts, or after daily business is over.

                                    Examples:
                                        '07:30:00'      The snapshots inside this table would all have the time '07:30:00'.
                                        '23:00:00'      The snapshots inside this table would all have the time '23:00:00'.
    " %}

    {% set sdts_alias_description = "
    sdts_alias::string              Defines the name of the snapshot date timestamp column inside the snapshot_table. It is optional,
                                    if not set will use the global variable `datavault4dbt.sdts_alias` set inside dbt_project.yml
    " %}

    {% set end_date_description = "
    end_date::timestamp             Defines the latest timestamp that should be available inside the snapshot_table.
    " %}


    {%- set start_date          = datavault4dbt.yaml_metadata_parser(name='start_date', yaml_metadata=yaml_metadata, parameter=start_date, required=True, documentation=start_date_description) -%}
    {%- set daily_snapshot_time = datavault4dbt.yaml_metadata_parser(name='daily_snapshot_time', yaml_metadata=yaml_metadata, parameter=daily_snapshot_time, required=True, documentation=daily_snapshot_time_description) -%}
    {%- set sdts_alias          = datavault4dbt.yaml_metadata_parser(name='sdts_alias', yaml_metadata=yaml_metadata, parameter=sdts_alias, required=False, documentation=sdts_alias_description) -%}
    {%- set end_date            = datavault4dbt.yaml_metadata_parser(name='end_date', yaml_metadata=yaml_metadata, parameter=end_date, required=False, documentation=end_date_description) -%}

    {%- set sdts_alias = datavault4dbt.replace_standard(sdts_alias, 'datavault4dbt.sdts_alias', 'sdts') -%}

    {# For Fusion static_analysis overwrite #}
    {% set static_analysis_config = datavault4dbt.get_static_analysis_config('control_snap_v0') %}
    {%- if datavault4dbt.is_something(static_analysis_config) -%}
        {{ config(static_analysis='off') }}
    {%- endif -%}

    {%- if var('datavault4dbt.use_premium_package', False) == True -%}
        {{ datavault4dbt_premium_package.insert_metadata_snap_v0(start_date=start_date,
                                                            daily_snapshot_time=daily_snapshot_time,
                                                            sdts_alias=sdts_alias,
                                                            end_date=end_date) }}
    {%- endif %}

    {{ adapter.dispatch('control_snap_v0', 'datavault4dbt')(start_date=start_date,
                                                            daily_snapshot_time=daily_snapshot_time,
                                                            sdts_alias=sdts_alias,
                                                            end_date=end_date) }}

{%- endmacro -%}

macro.datavault4dbt.control_snap_v1.macro_sql:
{%- macro control_snap_v1(yaml_metadata=none, control_snap_v0=none, log_logic=none, sdts_alias=none) -%}

    {% set control_snap_v0_description = "
    control_snap_v0::string             The name of the underlying version 0 control snapshot table. Needs to be
                                        available as a dbt model.
    " %}

    {% set log_logic_description = "
    log_logic::dictionary           Defining the desired durations of each granularity. Available granularities
                                    are 'daily', 'weekly', 'monthly', and 'yearly'. For each granularity the
                                    duration can be defined as an integer, and the time unit for that duration.
                                    The units include (in BigQuery): DAY, WEEK, MONTH, QUARTER, YEAR. Besides
                                    defining a duration and a unit for each granularity, there is also the option
                                    to set a granularity to 'forever'. E.g. reporting requires daily snapshots
                                    for 3 months, and after that the monthly snapshots should be kept forever.

                                    If log_logic is not set, no logic will be applied, and all snapshots will stay
                                    active. The other dynamic columns are calculated anyway.

                                    The duration is always counted from the current date.

                                    EXASOL: Due to a missing 'DAY OF WEEK' Function in Exasol, is_weekly is currently
                                            not supported and needs to be left out of the log_logic definition.

                                    Examples:
                                        {'daily': {'duration': 3,               This configuration would keep daily
                                                    'unit': 'MONTH',            snapshots for 3 months, weekly snapshots
                                                    'forever': 'FALSE'},          for 1 year, monthly snapshots for 5
                                        'weekly': {'duration': 1,               years and yearly snapshots forever.
                                                    'unit': 'YEAR'},            If 'forever' is not defined here, it
                                        'monthly': {'duration': 5,              is automatically set to 'FALSE'.
                                                    'unit': 'YEAR'},            therefore it could have been left out
                                        'yearly': {'forever': 'TRUE'} }         in the configuration for daily snapshots.

                                        {'daily': {'duration': 90,              This would keep daily snapshots for 90
                                                    'unit': 'DAY'},              days, and monthly snapshots forever.
                                            'monthly': {'forever': 'TRUE'}}
    " %}

    {% set sdts_alias_description = "
    sdts_alias::string          Defines the name of the snapshot date timestamp column inside the snapshot_table. 
                                It is optional, if not set will use the global variable `datavault4dbt.sdts_alias` 
                                set inside dbt_project.yml
    " %}

    {% set control_snap_v0  = datavault4dbt.yaml_metadata_parser(name='control_snap_v0', yaml_metadata=yaml_metadata, parameter=control_snap_v0, required=True, documentation=control_snap_v0_description) %}
    {% set log_logic        = datavault4dbt.yaml_metadata_parser(name='log_logic', yaml_metadata=yaml_metadata, parameter=log_logic, required=False, documentation=log_logic_description) %}
    {% set sdts_alias       = datavault4dbt.yaml_metadata_parser(name='sdts_alias', yaml_metadata=yaml_metadata, parameter=sdts_alias, required=False, documentation=sdts_alias_description) %}


    {%- set sdts_alias = datavault4dbt.replace_standard(sdts_alias, 'datavault4dbt.sdts_alias', 'sdts') -%}

    {# For Fusion static_analysis overwrite #}
    {% set static_analysis_config = datavault4dbt.get_static_analysis_config('control_snap_v1') %}
    {%- if datavault4dbt.is_something(static_analysis_config) -%}
        {{ config(static_analysis='off') }}
    {%- endif -%}

    {%- if var('datavault4dbt.use_premium_package', False) == True -%}
        {{ datavault4dbt_premium_package.insert_metadata_snap_v1(control_snap_v0=control_snap_v0,
                                                                        log_logic=log_logic,
                                                                        sdts_alias=sdts_alias) }}
    {%- endif %}
    
    {{ adapter.dispatch('control_snap_v1', 'datavault4dbt')(control_snap_v0=control_snap_v0,
                                                                        log_logic=log_logic,
                                                                        sdts_alias=sdts_alias) }}

{%- endmacro -%}

macro.datavault4dbt.eff_sat_v0.macro_sql:
{%- macro eff_sat_v0(yaml_metadata=none, source_model=none, tracked_hashkey=none,  src_ldts=none, src_rsrc=none, is_active_alias=none, source_is_single_batch=true, disable_hwm=false, additional_columns=none) -%}

    {% set additional_columns_description = "
    additional_columns::list | string       Additional columns from source system or derived columns which should be part of the eff_sat.
                                            The columns need to be available in all source models.
                                            Optional parameter, defaults to empty list.
    " %}

    {% set source_model             = datavault4dbt.yaml_metadata_parser(name='source_model', yaml_metadata=yaml_metadata, parameter=source_model, required=True, documentation='Name of the source model') %}
    {% set tracked_hashkey          = datavault4dbt.yaml_metadata_parser(name='tracked_hashkey', yaml_metadata=yaml_metadata, parameter=tracked_hashkey, required=True, documentation='Name of the hashkey column to be tracked') %}
    {% set src_ldts                 = datavault4dbt.yaml_metadata_parser(name='src_ldts', yaml_metadata=yaml_metadata, parameter=src_ldts, required=False, documentation='Name of the loaddate column in the source model. Optional.') %}
    {% set src_rsrc                 = datavault4dbt.yaml_metadata_parser(name='src_rsrc', yaml_metadata=yaml_metadata, parameter=src_rsrc, required=False, documentation='Name of the record source column in the source model. Optional.') %}
    {% set is_active_alias          = datavault4dbt.yaml_metadata_parser(name='is_active_alias', yaml_metadata=yaml_metadata, parameter=is_active_alias, required=False, documentation='Name of the new active flag column. Optional.') %}
    {% set source_is_single_batch   = datavault4dbt.yaml_metadata_parser(name='source_is_single_batch', yaml_metadata=yaml_metadata, parameter=source_is_single_batch, required=False, documentation='Whether the source contains only one batch. Optional, default True.') %}
    {% set disable_hwm              = datavault4dbt.yaml_metadata_parser(name='disable_hwm', yaml_metadata=yaml_metadata, parameter=disable_hwm, required=False, documentation='Whether the High Water Mark should be disabled or not. Optional.') %}
    {%- set additional_columns      = datavault4dbt.yaml_metadata_parser(name='additional_columns', yaml_metadata=yaml_metadata, parameter=additional_columns, required=False, documentation=additional_columns_description) -%}
    
    {# Applying the default aliases as stored inside the global variables, if src_ldts, src_rsrc, and ledts_alias are not set. #}
    {%- set src_ldts = datavault4dbt.replace_standard(src_ldts, 'datavault4dbt.ldts_alias', 'ldts') -%}
    {%- set src_rsrc = datavault4dbt.replace_standard(src_rsrc, 'datavault4dbt.rsrc_alias', 'rsrc') -%}
    {%- set is_active_alias = datavault4dbt.replace_standard(is_active_alias, 'datavault4dbt.is_active_alias', 'is_active') -%}

    {# For Fusion static_analysis overwrite #}
    {% set static_analysis_config = datavault4dbt.get_static_analysis_config('eff_sat_v0') %}
    {%- if datavault4dbt.is_something(static_analysis_config) -%}
        {{ config(static_analysis='off') }}
    {%- endif -%}

    {%- if var('datavault4dbt.use_premium_package', False) == True -%}
        {{ datavault4dbt_premium_package.insert_metadata_eff_sat(tracked_hashkey=tracked_hashkey,
                                         src_ldts=src_ldts,
                                         src_rsrc=src_rsrc,
                                         is_active_alias=is_active_alias,
                                         source_model=source_model,
                                         source_is_single_batch=source_is_single_batch,
                                         disable_hwm=disable_hwm,
                                         additional_columns=additional_columns)}}
    {%- endif %}

    {{ return(adapter.dispatch('eff_sat_v0', 'datavault4dbt')(tracked_hashkey=tracked_hashkey,
                                         src_ldts=src_ldts,
                                         src_rsrc=src_rsrc,
                                         is_active_alias=is_active_alias,
                                         source_model=source_model,
                                         source_is_single_batch=source_is_single_batch,
                                         disable_hwm=disable_hwm,
                                         additional_columns=additional_columns))
    }}
    
{%- endmacro -%}

macro.datavault4dbt.ma_sat_v0.macro_sql:
{%- macro ma_sat_v0(yaml_metadata=none, parent_hashkey=none, src_hashdiff=none, src_ma_key=none, src_payload=none, source_model=none, src_ldts=none, src_rsrc=none, additional_columns=none) -%}

    {% set parent_hashkey_description = "
    parent_hashkey::string                  Name of the hashkey column inside the stage of the object that this satellite is attached to.

                                            Examples:
                                                'hk_account_h'          The satellite would be attached to the hub account, which has the
                                                                        column 'hk_account_h' as a hashkey column.

                                                'hk_account_contact_l'  The satellite would be attached to the link between account and contact,
                                                                        which has the column 'hk_account_contact_l' as a hashkey column.
    " %}

    {% set src_hashdiff_description = "
    src_hashdiff::string                    Name of the hashdiff column of this satellite, that was created inside the staging area and is
                                            calculated out of the entire payload of this satellite. The stage must hold one hashdiff per
                                            satellite entity.

                                            Examples:
                                                'hd_account_data_sfdc_s'    Since we recommend naming the hashdiff column similar to the name
                                                                            of the satellite entity, just with a prefix, this would be the
                                                                            hashdiff column of the data satellite for account.
    " %}

    {% set src_ma_key_description = "
    src_ma_key::string|list of strings      Name(s) of the multi-active keys inside the staging area. Need to be the same ones, as
                                            defined in the stage model.

                                            Examples:
                                                'phonetype'                 The column 'phonetype' is the multi-active key inside the source
                                                                            model. That means, there is always only one combination of hashkey
                                                                            and multi-active key at a time.

                                                ['phonetype', 'company']    In this case, the combination of the two columns 'phonetype' and 'company'
                                                                            is treated as the multi-active key.
    " %}

    {% set src_payload_description = "
    src_payload::list of strings            A list of all the descriptive attributes that should be included in this satellite. Needs to be the
                                            columns that are fed into the hashdiff calculation of this satellite. Do not include the multi-active
                                            key in the payload of a multi-active satellite, it is included automatically!

                                            Examples:
                                                ['name', 'address', 'country', 'phone', 'email']    This satellite would hold the columns 'name',
                                                                                                    'address', 'country', 'phone' and 'email', coming
                                                                                                    out of the underlying staging area.
    " %}

    {% set source_model_description = "
    source_model::string                    Name of the underlying staging model, must be available inside dbt as a model.

                                            Examples:
                                                'stage_account'     This satellite is loaded out of the stage for account.
    " %}

    {% set src_ldts_description = "
    src_ldts::string                        Name of the ldts column inside the source model. Is optional, will use the global variable 'datavault4dbt.ldts_alias'.
                                            Needs to use the same column name as defined as alias inside the staging model.
    " %}

    {% set src_rsrc_description = "
    src_rsrc::string                        Name of the rsrc column inside the source model. Is optional, will use the global variable 'datavault4dbt.rsrc_alias'.
                                            Needs to use the same column name as defined as alias inside the staging model.
    " %}

    {% set additional_columns_description = "
    additional_columns::list | string       Additional columns from source system or derived columns which should be part of the ma_sat.
                                            The columns need to be available in all source models.
                                            Optional parameter, defaults to empty list.
    " %}

    {%- set parent_hashkey      = datavault4dbt.yaml_metadata_parser(name='parent_hashkey', yaml_metadata=yaml_metadata, parameter=parent_hashkey, required=True, documentation=parent_hashkey_description) -%}
    {%- set src_hashdiff        = datavault4dbt.yaml_metadata_parser(name='src_hashdiff', yaml_metadata=yaml_metadata, parameter=src_hashdiff, required=True, documentation=src_hashdiff_description) -%}
    {%- set src_ma_key          = datavault4dbt.yaml_metadata_parser(name='src_ma_key', yaml_metadata=yaml_metadata, parameter=src_ma_key, required=True, documentation=src_ma_key_description) -%}
    {%- set src_payload         = datavault4dbt.yaml_metadata_parser(name='src_payload', yaml_metadata=yaml_metadata, parameter=src_payload, required=True, documentation=src_payload_description) -%}
    {%- set source_model        = datavault4dbt.yaml_metadata_parser(name='source_model', yaml_metadata=yaml_metadata, parameter=source_model, required=True, documentation=source_model_description) -%}
    {%- set src_ldts            = datavault4dbt.yaml_metadata_parser(name='src_ldts', yaml_metadata=yaml_metadata, parameter=src_ldts, required=False, documentation=src_ldts_description) -%}
    {%- set src_rsrc            = datavault4dbt.yaml_metadata_parser(name='src_rsrc', yaml_metadata=yaml_metadata, parameter=src_rsrc, required=False, documentation=src_rsrc_description) -%}
    {%- set additional_columns  = datavault4dbt.yaml_metadata_parser(name='additional_columns', yaml_metadata=yaml_metadata, parameter=additional_columns, required=False, documentation=additional_columns_description) -%}
    
    {# Applying the default aliases as stored inside the global variables, if src_ldts and src_rsrc are not set. #}

    {%- set src_ldts = datavault4dbt.replace_standard(src_ldts, 'datavault4dbt.ldts_alias', 'ldts') -%}
    {%- set src_rsrc = datavault4dbt.replace_standard(src_rsrc, 'datavault4dbt.rsrc_alias', 'rsrc') -%}

    {# For Fusion static_analysis overwrite #}
    {% set static_analysis_config = datavault4dbt.get_static_analysis_config('ma_sat_v0') %}
    {%- if datavault4dbt.is_something(static_analysis_config) -%}
        {{ config(static_analysis='off') }}
    {%- endif -%}

    {%- if var('datavault4dbt.use_premium_package', False) == True -%}
        {{ datavault4dbt_premium_package.insert_metadata_ma_sat_v0(parent_hashkey=parent_hashkey,
                                         src_hashdiff=src_hashdiff,
                                         src_ma_key=src_ma_key,
                                         src_payload=src_payload,
                                         src_ldts=src_ldts,
                                         src_rsrc=src_rsrc,
                                         source_model=source_model,
                                         additional_columns=additional_columns) }}
    {%- endif %}

    {{ adapter.dispatch('ma_sat_v0', 'datavault4dbt')(parent_hashkey=parent_hashkey,
                                         src_hashdiff=src_hashdiff,
                                         src_ma_key=src_ma_key,
                                         src_payload=src_payload,
                                         src_ldts=src_ldts,
                                         src_rsrc=src_rsrc,
                                         source_model=source_model,
                                         additional_columns=additional_columns) }}

{%- endmacro -%}

macro.datavault4dbt.ma_sat_v1.macro_sql:
{%- macro ma_sat_v1(yaml_metadata=none, sat_v0=none, hashkey=none, hashdiff=none, ma_attribute=none, src_ldts=none, src_rsrc=none, ledts_alias=none, add_is_current_flag=false) -%}

    {% set sat_v0_description = "
    sat_v0::string                              Name of the underlying version 0 multi-active satellite.

                                                Examples:
                                                    'contact_phonenumber_0_s'   This satellite would be the version 1 satellite of the underlying
                                                                                version 0 phone number satellite for contacts.
    " %}

    {% set hashkey_description = "
    hashkey::string                             Name of the parent hashkey column inside the version 0 satellite. Would either be the hashkey of a
                                                hub or a link. Needs to be similar to the 'parent_hashkey' parameter inside the sat_v0 model.

                                                Examples:
                                                    'hk_contact_h'          The satellite would be attached to the hub contact, which has the
                                                                            column 'hk_contact_h' as a hashkey column.

                                                    'hk_order_contact_l'    The satellite would be attached to the link between order and contact,
                                                                            which has the column 'hk_order_contact_l' as a hashkey column.
    " %}

    {% set hashdiff_description = "
    hashdiff::string                            Name of the hashdiff column inside the underlying version 0 satellite. Needs to be similar to the
                                                'src_hashdiff' parameter inside the sat_v0 model. Must not include the ma_attribute in calculation.

                                                Examples:
                                                    'hd_contact_phonenumber_s'      Since we recommend naming the hashdiff column similar to the name
                                                                                    of the satellite entity, just with a prefix, this would be the
                                                                                    hashdiff column of the phone number satellite for contacts.
    " %}

    {% set ma_attribute_description = "
    ma_attribute::string|list of strings        Name of the multi active attribute inside the v0 satellite. This needs to be identified under the
                                                requirement that the combination of hashkey + ldts + ma_attribute is unique over the entire stage / satellite.

                                                Examples:
                                                    'phone_type'            Phone numbers are a good example of multi active data. One person could have an unlimited
                                                                            number of phone numbers, i. e. a mobile phone number, a home phone number, and a work phone
                                                                            number. therefore a contact has one active phone number per type per ldts and the phone_type
                                                                            uniquely identifies a record inside a hashkey+ldts combination.

                                                    ['phone_type', 'iid']   If a contact could have multiple mobile phone numbers, the phone_type alone would not be
                                                                            enough to uniquely identify a record inside a hashkey+ldts combination. Additionally the attribute
                                                                            iid, which is an increasing identifier within a phone_type, is added as a ma_attribute.
    " %}

    {% set src_ldts_description = "
    src_ldts::string                            Name of the ldts column inside the source models. Is optional, will use the global variable 'datavault4dbt.ldts_alias'.
                                                Needs to use the same column name as defined as alias inside the staging model.
    " %}

    {% set src_rsrc_description = "
    src_rsrc::string                            Name of the rsrc column inside the source models. Is optional, will use the global variable 'datavault4dbt.rsrc_alias'.
                                                Needs to use the same column name as defined as alias inside the staging model.
    " %}

    {% set ledts_alias_description = "
    ledts_alias::string                         Desired alias for the load end date column. Is optional, will use the global variable 'datavault4dbt.ledts_alias' if
                                                set here.
    " %}

    {% set add_is_current_flag_description = "
    add_is_current_flag::boolean                Optional parameter to add a new column to the v1 sat based on the load end date timestamp (ledts). Default is false. If
                                                set to true it will add this is_current flag to the v1 sat. For each record this column will be set to true if the load
                                                end date time stamp is equal to the variable end of all times. If its not, then the record is not current therefore it
                                                will be set to false.
    " %}

    {%- set sat_v0              = datavault4dbt.yaml_metadata_parser(name='sat_v0', yaml_metadata=yaml_metadata, parameter=sat_v0, required=True, documentation=sat_v0_description) -%}
    {%- set hashkey             = datavault4dbt.yaml_metadata_parser(name='hashkey', yaml_metadata=yaml_metadata, parameter=hashkey, required=True, documentation=hashkey_description) -%}
    {%- set hashdiff            = datavault4dbt.yaml_metadata_parser(name='hashdiff', yaml_metadata=yaml_metadata, parameter=hashdiff, required=True, documentation=hashdiff_description) -%}
    {%- set ma_attribute        = datavault4dbt.yaml_metadata_parser(name='ma_attribute', yaml_metadata=yaml_metadata, parameter=ma_attribute, required=True, documentation=ma_attribute_description) -%}
    {%- set src_ldts            = datavault4dbt.yaml_metadata_parser(name='src_ldts', yaml_metadata=yaml_metadata, parameter=src_ldts, required=False, documentation=src_ldts_description) -%}
    {%- set src_rsrc            = datavault4dbt.yaml_metadata_parser(name='src_rsrc', yaml_metadata=yaml_metadata, parameter=src_rsrc, required=False, documentation=src_rsrc_description) -%}
    {%- set ledts_alias         = datavault4dbt.yaml_metadata_parser(name='ledts_alias', yaml_metadata=yaml_metadata, parameter=ledts_alias, required=False, documentation=ledts_alias_description) -%}
    {%- set add_is_current_flag = datavault4dbt.yaml_metadata_parser(name='add_is_current_flag', yaml_metadata=yaml_metadata, parameter=add_is_current_flag, required=False, documentation=add_is_current_flag_description) -%}

    {# Applying the default aliases as stored inside the global variables, if src_ldts, src_rsrc, and ledts_alias are not set. #}

    {%- set src_ldts = datavault4dbt.replace_standard(src_ldts, 'datavault4dbt.ldts_alias', 'ldts') -%}
    {%- set src_rsrc = datavault4dbt.replace_standard(src_rsrc, 'datavault4dbt.rsrc_alias', 'rsrc') -%}
