macro.datavault4dbt.pit.macro_sql:
{%- macro pit(yaml_metadata=none, tracked_entity=none, hashkey=none, sat_names=none, snapshot_relation=none, dimension_key=none, snapshot_trigger_column=none, ldts=none, custom_rsrc=none, ledts=none, sdts=none, pit_type=none, refer_to_ghost_records=True, snapshot_optimization=False) -%}

    {% set tracked_entity_description = "
    tracked_entity::string              Name of the tracked Hub entity. Must be available as a model inside the dbt project.
    " %}

    {% set hashkey_description = "
    hashkey::string                     The name of the hashkey column inside the previously referred Hub entity.
    " %}

    {% set sat_names_description = "
    sat_names::list of strings          A list of all the satellites that should be included in this PIT table. Can only be satellites
                                        that are attached to the tracked Hub, and should typically include all those satellites.
                                        You should always refer here to the version 1 satellites, since those hold the load-end-date.
                                        The macro currently supports regular satellites and nh-satellites.
    " %}

    {% set snapshot_relation_description = "
    snapshot_relation::string           The name of the snapshot relation. It needs to be available as a model inside this dbt project.
    " %}

    {% set snapshot_trigger_column_description = "
    snapshot_trigger_column::string     The name of the column inside the previously mentioned snapshot relation, that is boolean and
                                        identifies the snapshots that should be included in the PIT table.
    " %}

    {% set dimension_key_description = "
    dimension_key::string               The desired name of the dimension key inside the PIT table. Should follow some naming conventions.
                                        Recommended is the name of the hashkey with a '_d' suffix.
    " %}

    {% set ldts_description = "
    ldts::string                        Name of the ldts column inside all source models. Is optional, will use the global variable
                                        'datavault4dbt.ldts_alias'. Needs to use the same column name as defined as alias inside the staging model.
    " %}

    {% set custom_rsrc_description = "
    custom_rsrc::string                 A custom string that should be inserted into the 'rsrc' column inside the PIT table. Since
                                        a PIT table is a business vault entity, the technical record source is no longer used here.
                                        Is optional, if not defined, no column is added.
    " %}

    {% set ledts_description = "
    ledts::string                       Name of the load-end-date column inside the satellites. Is optional, will use the global variable
                                        'datavault4dbt.ledts_alias' if not set here.
    " %}

    {% set sdts_description = "
    sdts::string                        Name of the snapshot date timestamp column inside the snapshot table. It is optional, will use the 
                                        global variable 'datavault4dbt.sdts_alias' if not set here.
    " %}

    {% set pit_type_description = "
    pit_type::string                    String to insert into the 'pit_type' column. Has to be prefixed by a !.
                                        Allows for future implementations of other PIT variants, like T-PITs etc.
                                        Can be set freely, something like 'PIT' could be the default. 
                                        Is optional, if not set, no column will be added.
    " %}

    {% set refer_to_ghost_records_description = "
    refer_to_ghost_records::boolean     Value to define if a NULL satellite hashkey should be replaced by the unknown key.
                                        Optional parameter, default is True.
    " %}

    {%- set snapshot_optimization_description = "
    snapshot_optimization::boolean     If set to True, and if the model is run in incremental mode, only the relevant snapshots
                                        (i.e. those that are newer (or equal e.g. because of late arriving data) than the max sdts in the existing PIT table) will be considered.
                                        This can significantly improve performance of incremental loads on large snapshot tables.
                                        If set to True, the model needs to be configured with a unique_key constraint as there may be updates due to the late arriving data.
                                        Affected Adapters: Snowflake only! Optional parameter, default is False.
    " -%}

    {%- set tracked_entity          = datavault4dbt.yaml_metadata_parser(name='tracked_entity', yaml_metadata=yaml_metadata, parameter=tracked_entity, required=True, documentation=tracked_entity_description) -%}
    {%- set hashkey                 = datavault4dbt.yaml_metadata_parser(name='hashkey', yaml_metadata=yaml_metadata, parameter=hashkey, required=True, documentation=hashkey_description) -%}
    {%- set sat_names               = datavault4dbt.yaml_metadata_parser(name='sat_names', yaml_metadata=yaml_metadata, parameter=sat_names, required=True, documentation=sat_names_description) -%}
    {%- set snapshot_relation       = datavault4dbt.yaml_metadata_parser(name='snapshot_relation', yaml_metadata=yaml_metadata, parameter=snapshot_relation, required=True, documentation=snapshot_relation_description) -%}
    {%- set dimension_key           = datavault4dbt.yaml_metadata_parser(name='dimension_key', yaml_metadata=yaml_metadata, parameter=dimension_key, required=True, documentation=dimension_key_description) -%}
    {%- set snapshot_trigger_column = datavault4dbt.yaml_metadata_parser(name='snapshot_trigger_column', yaml_metadata=yaml_metadata, parameter=snapshot_trigger_column, required=False, documentation=snapshot_trigger_column_description) -%}
    {%- set ldts                    = datavault4dbt.yaml_metadata_parser(name='ldts', yaml_metadata=yaml_metadata, parameter=ldts, required=False, documentation=ldts_description) -%}
    {%- set custom_rsrc             = datavault4dbt.yaml_metadata_parser(name='custom_rsrc', yaml_metadata=yaml_metadata, parameter=custom_rsrc, required=False, documentation=custom_rsrc_description) -%}
    {%- set ledts                   = datavault4dbt.yaml_metadata_parser(name='ledts', yaml_metadata=yaml_metadata, parameter=ledts, required=False, documentation=ledts_description) -%}
    {%- set sdts                    = datavault4dbt.yaml_metadata_parser(name='sdts', yaml_metadata=yaml_metadata, parameter=sdts, required=False, documentation=sdts_description) -%}
    {%- set pit_type                = datavault4dbt.yaml_metadata_parser(name='pit_type', yaml_metadata=yaml_metadata, parameter=pit_type, required=False, documentation=pit_type_description) -%}
    {%- set refer_to_ghost_records  = datavault4dbt.yaml_metadata_parser(name='refer_to_ghost_records', yaml_metadata=yaml_metadata, parameter=refer_to_ghost_records, required=False, documentation=pit_type_description) -%}
    {%- set snapshot_optimization  = datavault4dbt.yaml_metadata_parser(name='snapshot_optimization', yaml_metadata=yaml_metadata, parameter=snapshot_optimization, required=False, documentation=snapshot_optimization_description) -%}

    {# Applying the default aliases as stored inside the global variables, if ldts, sdts and ledts are not set. #}

    {%- set ldts = datavault4dbt.replace_standard(ldts, 'datavault4dbt.ldts_alias', 'ldts') -%}
    {%- set ledts = datavault4dbt.replace_standard(ledts, 'datavault4dbt.ledts_alias', 'ledts') -%}
    {%- set sdts = datavault4dbt.replace_standard(sdts, 'datavault4dbt.sdts_alias', 'sdts') -%}

        {# For Fusion static_analysis overwrite #}
    {% set static_analysis_config = datavault4dbt.get_static_analysis_config('pit') %}
    {%- if datavault4dbt.is_something(static_analysis_config) -%}
        {{ config(static_analysis='off') }}
    {%- endif -%}

    {%- if var('datavault4dbt.use_premium_package', False) == True -%}
        {{ datavault4dbt_premium_package.insert_metadata_pit(pit_type=pit_type,
                                                        tracked_entity=tracked_entity,
                                                        hashkey=hashkey,
                                                        sat_names=sat_names,
                                                        ldts=ldts,
                                                        sdts=sdts,
                                                        custom_rsrc=custom_rsrc,
                                                        ledts=ledts,
                                                        snapshot_relation=snapshot_relation,
                                                        snapshot_trigger_column=snapshot_trigger_column,
                                                        dimension_key=dimension_key,
                                                        refer_to_ghost_records=refer_to_ghost_records,
                                                        snapshot_optimization=snapshot_optimization) }}
    {%- endif %}
    
    {{ return(adapter.dispatch('pit','datavault4dbt')(pit_type=pit_type,
                                                        tracked_entity=tracked_entity,
                                                        hashkey=hashkey,
                                                        sat_names=sat_names,
                                                        ldts=ldts,
                                                        sdts=sdts,
                                                        custom_rsrc=custom_rsrc,
                                                        ledts=ledts,
                                                        snapshot_relation=snapshot_relation,
                                                        snapshot_trigger_column=snapshot_trigger_column,
                                                        dimension_key=dimension_key,
                                                        refer_to_ghost_records=refer_to_ghost_records,
                                                        snapshot_optimization=snapshot_optimization)) }}

{%- endmacro -%}

macro.datavault4dbt.rec_track_sat.macro_sql:
{%- macro rec_track_sat(yaml_metadata=none, tracked_hashkey=none, source_models=none, src_ldts=none, src_rsrc=none, src_stg=none, disable_hwm=false, additional_columns=none) -%}

    {% set tracked_hashkey_description = "
    tracked_hashkey::string         The name of the hashkey column you want to track. Needs to be available in the underlying staging layer. If you want to track multiple
                                    hashkeys out of one stage, you need to create one record tracking satellite for each hashkey.

                                    Examples:
                                        'hk_contact_h'              This record tracking satellite tracks the appearance of the hashkey for the contact hub.

                                        'hk_contact_account_l'      This record tracking satellite tracks the appearance of the hashkey for the link between contacts and accounts.
    " %}

    {% set source_models_description = "
    source_models::dictionary       Dictionary with information about the source model. The key of the dict is the name of the source model, and the value
                                    is another dictionary. This inner dictionary requires to have the keys 'rsrc_static', and optionally the key 'hk_column'.

                                    Examples:
                                        {'stage_account': {'hk_column': 'hk_account_h',                         This record tracking satellite tracks the hashkey 'hk_account_h' inside the
                                                        'rsrc_static': '*/SAP/Accounts/*'}}                     source model named 'stage_account'.

                                        {'stage_contact': {'rsrc_static': '*/SALESFORCE/Contact/*'},            This tracks the appearance of one hub hashkey that is loaded from the two source
                                        'stage_partner': {'hk_column': 'hk_partner_h',                          models 'stage_contact' and 'stage_partner'. For 'stage_account' no 'hk_column' is defined,
                                                          'rsrc_static': '*/SALESFORCE/Partners/*'}}            and therefore the input of the upper level variable 'tracked_hashkey' will be used.
                                                                                                                For 'stage_partner' the name of the hashkey column differs from the upper level definition
                                                                                                                and therefore this other name is set under the variable 'hk_column.'

                                                                                                                The 'rsrc_static' attribute defines a STRING or a list of strings that will always be 
                                                                                                                the same over all loads of one source.
                                                                                                                Something like this needs to be identified for each source system,
                                                                                                                and strongly depends on the actual content of the rsrc column inside the stage.
                                                                                                                Sometimes the rsrc column includes the ldts of each load and could look something
                                                                                                                like this: 'SALESFORCE/Partners/2022-01-01T07:00:00'. Obviously the timestamp part
                                                                                                                inside that rsrc would change from load to load, and we now need to identify parts of
                                                                                                                it that will be static over all loads. Here it would be 'SALESFORCE/Partners'. This static
                                                                                                                part is now enriched by wildcard expressions (in BigQuery that would be '*') to catch
                                                                                                                the variable part of the rsrc values.
                                                                                                                If my rsrc would be the same over all loads, then it might look something like
                                                                                                                this: 'SAP/Accounts/'. Here everything would be static over all loads and
                                                                                                                therefore I would set rsrc_static to 'SAP/Accounts/' without any wildcards in place.
                                                                                                                If the rsrc_static is defined as solely the wildcard '*' for any source then 
                                                                                                                this record source performance lookup will not be executed. 
                                                                                                                If the rsrc_static is not set in one of the source models, then the assumption is made that
                                                                                                                or this source there is always the same value for any record in the record source column. 
                                                                                                                The macro will then get automatically this unique value querying the source model.
    " %}

    {% set src_ldts_description = "
    src_ldts::string                Name of the ldts column inside the source models. Is optional, will use the global variable 'datavault4dbt.ldts_alias'.
                                    Needs to use the same column name as defined as alias inside the staging model.
    " %}

    {% set src_rsrc_description = "
    src_rsrc::string                Name of the rsrc column inside the source models. Is optional, will use the global variable 'datavault4dbt.rsrc_alias'.
                                    Needs to use the same column name as defined as alias inside the staging model.
    " %}

    {% set src_stg_description = "
    src_stg::string                 Name of the source stage model. Is optional, will use the global variable  'datavault4dbt.stg_alias'.
    " %}

    {% set additional_columns_description = "
    additional_columns::list | string       Additional columns from source system or derived columns which should be part of the rec_track_sat.
                                            The columns need to be available in all source models.
                                            Optional parameter, defaults to empty list.
    " %}

    {%- set tracked_hashkey = datavault4dbt.yaml_metadata_parser(name='tracked_hashkey', yaml_metadata=yaml_metadata, parameter=tracked_hashkey, required=True, documentation=tracked_hashkey_description) -%}
    {%- set source_models   = datavault4dbt.yaml_metadata_parser(name='source_models', yaml_metadata=yaml_metadata, parameter=source_models, required=True, documentation=source_models_description) -%}
    {%- set src_ldts        = datavault4dbt.yaml_metadata_parser(name='src_ldts', yaml_metadata=yaml_metadata, parameter=src_ldts, required=False, documentation=src_ldts_description) -%}
    {%- set src_rsrc        = datavault4dbt.yaml_metadata_parser(name='src_rsrc', yaml_metadata=yaml_metadata, parameter=src_rsrc, required=False, documentation=src_rsrc_description) -%}
    {%- set src_stg         = datavault4dbt.yaml_metadata_parser(name='src_stg', yaml_metadata=yaml_metadata, parameter=src_stg, required=False, documentation=src_stg_description) -%}
    {%- set disable_hwm     = datavault4dbt.yaml_metadata_parser(name='disable_hwm', yaml_metadata=yaml_metadata, parameter=disable_hwm, required=False, documentation='Whether the High Water Mark should be turned off. Optional, default False.') -%}
    {%- set additional_columns      = datavault4dbt.yaml_metadata_parser(name='additional_columns', yaml_metadata=yaml_metadata, parameter=additional_columns, required=False, documentation=additional_columns_description) -%}

    {# Applying the default aliases as stored inside the global variables, if src_ldts and src_rsrc are not set. #}

    {%- set src_ldts = datavault4dbt.replace_standard(src_ldts, 'datavault4dbt.ldts_alias', 'ldts') -%}
    {%- set src_rsrc = datavault4dbt.replace_standard(src_rsrc, 'datavault4dbt.rsrc_alias', 'rsrc') -%}
    {%- set src_stg = datavault4dbt.replace_standard(src_stg, 'datavault4dbt.stg_alias', 'stg') -%}

    {# For Fusion static_analysis overwrite #}
    {% set static_analysis_config = datavault4dbt.get_static_analysis_config('rec_track_sat') %}
    {%- if datavault4dbt.is_something(static_analysis_config) -%}
        {{ config(static_analysis='off') }}
    {%- endif -%}

    {%- if var('datavault4dbt.use_premium_package', False) == True -%}
        {{ datavault4dbt_premium_package.insert_metadata_rec_sat(tracked_hashkey=tracked_hashkey,
                                                                      source_models=source_models,
                                                                      src_ldts=src_ldts,
                                                                      src_rsrc=src_rsrc,
                                                                      src_stg=src_stg,
                                                                      disable_hwm=disable_hwm,
                                                                      additional_columns=additional_columns) }}
    {%- endif %}
    
    {{ return(adapter.dispatch('rec_track_sat', 'datavault4dbt')(tracked_hashkey=tracked_hashkey,
                                                                      source_models=source_models,
                                                                      src_ldts=src_ldts,
                                                                      src_rsrc=src_rsrc,
                                                                      src_stg=src_stg,
                                                                      disable_hwm=disable_hwm,
                                                                      additional_columns=additional_columns)) }}

{%- endmacro -%}

macro.datavault4dbt.ref_hub.macro_sql:
