{%- macro default__sat_v1(sat_v0, hashkey, hashdiff, src_ldts, src_rsrc, ledts_alias, add_is_current_flag, include_payload) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set is_current_col_alias = var('datavault4dbt.is_current_col_alias', 'IS_CURRENT') -%}

{%- set source_relation = ref(sat_v0) -%}

{%- set all_columns = datavault4dbt.source_columns(source_relation=source_relation) -%}
{%- set exclude = [hashkey, hashdiff, src_ldts, src_rsrc] -%}

{%- set source_columns_to_select = datavault4dbt.process_columns_to_select(all_columns, exclude) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Calculate ledts based on the ldts of the earlier record. #}
end_dated_source AS (

    SELECT
        {{ hashkey }},
        {{ hashdiff }},
        {{ src_rsrc }},
        {{ src_ldts }},
        COALESCE(LEAD(TIMESTAMP_SUB({{ src_ldts }}, INTERVAL 1 MICROSECOND)) OVER (PARTITION BY {{ hashkey }} ORDER BY {{ src_ldts }}),{{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}) as {{ ledts_alias }}
        {%- if include_payload -%},
            {{ datavault4dbt.print_list(source_columns_to_select) }}
        {%- endif %}
    FROM {{ source_relation }}

)

SELECT
    {{ hashkey }},
    {{ hashdiff }},
    {{ src_rsrc }},
    {{ src_ldts }},
    {{ ledts_alias }}
    {%- if add_is_current_flag %},
        CASE WHEN {{ ledts_alias }} = {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
        THEN TRUE
        ELSE FALSE
        END AS {{ is_current_col_alias }}
    {% endif -%}
    {%- if include_payload -%},
        {{ datavault4dbt.print_list(source_columns_to_select) }}
    {%- endif %}
FROM end_dated_source

{%- endmacro -%}

macro.datavault4dbt.databricks__control_.macro_sql:
{%- macro databricks__control_snap_v1(control_snap_v0, log_logic, sdts_alias) -%}

{# Sample intervals
   {%-set log_logic = {'daily': {'duration': 3,
                                'unit': 'MONTH',
                                'forever': 'FALSE'},
                      'weekly': {'duration': 1,
                                 'unit': 'YEAR'},
                      'monthly': {'duration': 5,
                                  'unit': 'YEAR'},
                      'yearly': {'forever': 'TRUE'} } %} 
#}

{%- if log_logic is not none %}
    {%- for interval in log_logic.keys() %}
        {%- if 'forever' not in log_logic[interval].keys() -%}
            {% do log_logic[interval].update({'forever': 'FALSE'}) %}
        {%- endif -%}
    {%- endfor -%}
{%- endif %}

{%- set v0_relation = ref(control_snap_v0) -%}
{%- set ns = namespace(forever_status=FALSE) %}

{%- set snapshot_trigger_column = var('datavault4dbt.snapshot_trigger_column', 'is_active') -%}

WITH

latest_row AS (

    SELECT
        {{ sdts_alias }}
    FROM {{ v0_relation }}
    ORDER BY {{ sdts_alias }} DESC
    LIMIT 1

),

virtual_logic AS (

    SELECT
        c.{{ sdts_alias }},
        c.replacement_sdts,
        c.force_active,
        {%- if log_logic is none %}
        TRUE as {{ snapshot_trigger_column }},
        {%- else %}
        CASE
            WHEN
            {% if 'daily' in log_logic.keys() %}
                {%- if log_logic['daily']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' -%}
                    (1=1)
                {%- else %}

                    {%- set daily_duration = log_logic['daily']['duration'] -%}
                    {%- set daily_unit = log_logic['daily']['unit'] -%}

                    (c.{{ sdts_alias }} BETWEEN TRY_SUBTRACT(CURRENT_TIMESTAMP(), INTERVAL '{{ daily_duration }}' {{ daily_unit }}) AND CURRENT_TIMESTAMP())
                {%- endif -%}
            {%- endif %}

            {%- if 'weekly' in log_logic.keys() %}
            OR
                {%- if log_logic['weekly']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' -%}
                    (c.is_weekly = TRUE)
                {%- else %}

                    {%- set weekly_duration = log_logic['weekly']['duration'] -%}
                    {%- set weekly_unit = log_logic['weekly']['unit'] -%}

                    (
                (c.{{ sdts_alias }} BETWEEN TRY_SUBTRACT(CURRENT_TIMESTAMP(), INTERVAL '{{ weekly_duration }}' {{ weekly_unit }}) AND CURRENT_TIMESTAMP() )
                AND
                (c.is_weekly = TRUE)
            )
                {%- endif -%}
            {% endif -%}

            {%- if 'monthly' in log_logic.keys() %}
            OR
                {%- if log_logic['monthly']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' -%}
                    (c.is_monthly = TRUE)
                {%- else %}

                    {%- set monthly_duration = log_logic['monthly']['duration'] -%}
                    {%- set monthly_unit = log_logic['monthly']['unit'] -%}

                    (
                (c.{{ sdts_alias }} BETWEEN TRY_SUBTRACT(CURRENT_TIMESTAMP(), INTERVAL '{{ monthly_duration }}' {{ monthly_unit }}) AND CURRENT_TIMESTAMP() )
                AND
                (c.is_monthly = TRUE)
            )
                {%- endif -%}
            {% endif -%}

            {%- if 'yearly' in log_logic.keys() %}
            OR
                {%- if log_logic['yearly']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' -%}
                    (c.is_yearly = TRUE)
                {%- else %}

                    {%- set yearly_duration = log_logic['yearly']['duration'] -%}
                    {%- set yearly_unit = log_logic['yearly']['unit'] -%}

                    (
                (c.{{ sdts_alias }} BETWEEN TRY_SUBTRACT(CURRENT_TIMESTAMP(), INTERVAL '{{ yearly_duration }}' {{ yearly_unit }}) AND CURRENT_TIMESTAMP() )
                AND
                (c.is_yearly = TRUE)
            )
                {%- endif -%}
            {% endif %}
            THEN TRUE
            ELSE FALSE

        END AS {{ snapshot_trigger_column }},
        {%- endif %}

        CASE
            WHEN l.{{ sdts_alias }} IS NULL THEN FALSE
            ELSE TRUE
        END AS is_latest,

        c.caption,
        c.is_hourly,
        c.is_daily,
        c.is_weekly,
        c.is_monthly,
        c.is_yearly,
        CASE
            WHEN EXTRACT(YEAR FROM c.{{ sdts_alias }}) = EXTRACT(YEAR FROM CURRENT_DATE()) THEN TRUE
            ELSE FALSE
        END AS is_current_year,
        CASE
            WHEN EXTRACT(YEAR FROM c.{{ sdts_alias }}) = EXTRACT(YEAR FROM CURRENT_DATE())-1 THEN TRUE
            ELSE FALSE
        END AS is_last_year,
        CASE
            WHEN c.{{ sdts_alias }} BETWEEN TRY_SUBTRACT(CURRENT_TIMESTAMP(), INTERVAL '1' YEAR) AND CURRENT_TIMESTAMP() THEN TRUE
            ELSE FALSE
        END AS is_rolling_year,
        CASE
            WHEN c.{{ sdts_alias }} BETWEEN TRY_SUBTRACT(CURRENT_TIMESTAMP(), INTERVAL '2' YEAR) AND TRY_SUBTRACT(CURRENT_TIMESTAMP(), INTERVAL '1' YEAR) THEN TRUE
            ELSE FALSE
        END AS is_last_rolling_year,
        c.comment
    FROM {{ v0_relation }} c
    LEFT JOIN latest_row l
        ON c.{{ sdts_alias }} = l.{{ sdts_alias }}

),

active_logic_combined AS (

    SELECT 
        {{ sdts_alias }},
        replacement_sdts,
        CASE
            WHEN force_active AND {{ snapshot_trigger_column }} THEN TRUE
            WHEN NOT force_active OR NOT {{ snapshot_trigger_column }} THEN FALSE
        END AS {{ snapshot_trigger_column }},
        is_latest, 
        caption,
        is_hourly,
        is_daily,
        is_weekly,
        is_monthly,
        is_yearly,
        is_current_year,
        is_last_year,
        is_rolling_year,
        is_last_rolling_year,
        comment
    FROM virtual_logic

)

SELECT * FROM active_logic_combined

{%- endmacro -%}

macro.datavault4dbt.databricks__eff_sat_.macro_sql:
{%- macro databricks__eff_sat_v0(source_model, tracked_hashkey, src_ldts, src_rsrc, is_active_alias, source_is_single_batch, disable_hwm, additional_columns) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ns = namespace(last_cte= "") -%}

{%- set source_relation = ref(source_model) -%}

{# Select the additional_columns and put them in an array. If additional_colums is none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set tracked_hashkey = datavault4dbt.escape_column_names(tracked_hashkey) -%}
{%- set is_active_alias = datavault4dbt.escape_column_names(is_active_alias) -%}
{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}

{%- set unknown_value_rsrc = var('datavault4dbt.default_unknown_rsrc', 'SYSTEM') -%}

{%- set is_active_datatype = var('datavault4dbt.is_active_datatype', 'Boolean') -%}

{{ log('columns to select: '~final_columns_to_select, false) }}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{#
    In all cases, the source model is selected, and optionally a HWM is applied. 
#}
source_data AS (

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ src_ldts }},
        {{ src_rsrc }}
    FROM {{ source_relation }} src
    WHERE {{ src_ldts }} NOT IN ('{{ datavault4dbt.beginning_of_all_times() }}', '{{ datavault4dbt.end_of_all_times() }}')
    {%- if is_incremental() and not disable_hwm %}
    AND src.{{ src_ldts }} > (
        SELECT
            MAX({{ src_ldts }})
        FROM {{ this }}
        WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    )
    {%- endif %}
),

{#
    In all incremental cases, the current status for each hashkey is selected from the existing Effectivity Satellite.
#}
{%- if is_incremental() %}
current_status AS (

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ is_active_alias }},
        {{ src_rsrc }}
    FROM {{ this }}
    QUALIFY 
        ROW_NUMBER() OVER(PARTITION BY {{ tracked_hashkey }} ORDER BY {{ src_ldts }} DESC) = 1

),
{% endif %}

{#
    This block is for multi-batch processing. 
#}
{% if not source_is_single_batch %}

    {#
        List of all Hashkeys with their date of first appearance in the source model.
    #}
    hashkeys AS (

        SELECT 
            {{ tracked_hashkey }},
            MIN({{ src_ldts }}) as first_appearance
        FROM source_data
        GROUP BY {{ tracked_hashkey }}

    ),

    {#
        Distinct list of load dates in the multi-batch source.
    #}
    load_dates AS (

        SELECT Distinct
            {{ src_ldts }}
        FROM source_data
        
    ),

    {#
        All combinations of hashkeys and loaddates, for loaddates after the first appearance of a hashkey.
    #}
    history AS (

        SELECT 
            hk.{{ tracked_hashkey }},
            ld.{{ src_ldts }}
        FROM hashkeys hk
        CROSS JOIN load_dates ld
        WHERE ld.{{ src_ldts }} >= hk.first_appearance

    ),

    {#
        All theoretical combinations are checked against the actual occurences of hashkeys in each batch / loaddate.
        If a Hashkey is part of a load/batch, is_active_alias is set to true, because the hashkey was active in that load/batch.
        If a Hashkey is not part of a load/batch, is_active_alias is set to false, because the hashkey was not active in that load/batch.
    #}
    is_active AS (

        SELECT
            h.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            src.{{ col }},
            {% endfor -%}
            h.{{ src_ldts }},
            COALESCE(src.{{ src_rsrc }}, '{{ unknown_value_rsrc }}') AS {{ src_rsrc }},
            CASE 
                WHEN src.{{ tracked_hashkey }} IS NULL THEN 0
                ELSE 1 
            END as {{ is_active_alias }}
        FROM history h
        LEFT JOIN source_data src
            ON src.{{ tracked_hashkey }} = h.{{ tracked_hashkey }}
            AND src.{{ src_ldts }} = h.{{ src_ldts }}

    ),

    {#
        The rows are deduplicated on the is_active_alias, to only include status changes. 
    #}
    deduplicated_incoming AS (

        SELECT
            is_active.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            is_active.{{ col }},
            {% endfor -%}
            is_active.{{ src_ldts }},
            is_active.{{ src_rsrc }},
            is_active.{{ is_active_alias }} 

        FROM is_active
        QUALIFY 
            CASE 
                WHEN is_active.{{ is_active_alias }} = LAG(is_active.{{ is_active_alias }}) OVER (PARTITION BY {{ tracked_hashkey }} ORDER BY {{ src_ldts }}) THEN FALSE
                ELSE TRUE
            END

    ),

    {% set ns.last_cte = 'deduplicated_incoming' %}

{#
    This block is for single-batch processing
#}
{% else %}

    {#
        In initial loads of single-batch eff sats, every hashkey of the source is set to active.
    #}
    new_hashkeys AS (

        SELECT DISTINCT
            src.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            src.{{ col }},
            {% endfor -%}
            src.{{ src_ldts }},
            src.{{ src_rsrc }},
            1 as {{ is_active_alias }}
        FROM source_data src

        {#
            For incremental runs of single-batch eff sats, only hashkeys that are not active right now are set to active. 
            This automatically includes totally new hashkeys, or hashkeys that are currently set to inactive.
        #}
        {% if is_incremental() %}
            LEFT JOIN current_status cs
                ON src.{{ tracked_hashkey }} = cs.{{ tracked_hashkey }}
                AND cs.{{ is_active_alias }} = cast(1 as {{ is_active_datatype }})
            WHERE cs.{{ tracked_hashkey }} IS NULL
        {% endif %}

    ),

    {% set ns.last_cte = 'new_hashkeys' %}

{% endif %}

{#
    In all incremental runs, the source needs to be scanned for all currently active hashkeys. 
    If they are no longer present, they will be deactived. 
#}
{%- if is_incremental() %}

    {%- if not source_is_single_batch %}
        disappeared_hashkeys AS (

            SELECT DISTINCT 
                cs.{{ tracked_hashkey }},
                {% for col in additional_columns -%}
                null as {{ col }},
                {% endfor -%}
                ldts.min_ldts as {{ src_ldts }},
                '{{unknown_value_rsrc}}' AS {{ src_rsrc }},
                0 as {{ is_active_alias }}
            FROM current_status cs
            LEFT JOIN (
                SELECT 
                    MIN({{ src_ldts }}) as min_ldts
                FROM deduplicated_incoming) ldts
                ON 1 = 1
            LEFT JOIN deduplicated_incoming src
                ON src.{{ tracked_hashkey }} = cs.{{ tracked_hashkey }}
                AND  src.{{ src_ldts }} = ldts.min_ldts
            WHERE
                cs.{{ is_active_alias }} = cast(1 as {{ is_active_datatype }})
                AND src.{{ tracked_hashkey }} IS NULL
                AND ldts.min_ldts IS NOT NULL

        ),
    {% else %}
        disappeared_hashkeys AS (

            SELECT DISTINCT 
                cs.{{ tracked_hashkey }},
                {% for col in additional_columns -%}
                null as {{ col }},
                {% endfor -%}
                ldts.min_ldts as {{ src_ldts }},
                '{{unknown_value_rsrc}}' AS {{ src_rsrc }},
                0 as {{ is_active_alias }}
            FROM current_status cs
            LEFT JOIN (
                SELECT 
                    MIN({{ src_ldts }}) as min_ldts
                FROM source_data) ldts
                ON 1 = 1
            WHERE NOT EXISTS (
                SELECT 
                    1 
                FROM source_data src
                WHERE src.{{ tracked_hashkey }} = cs.{{ tracked_hashkey }}
            )
            AND cs.{{ is_active_alias }} = cast(1 as {{ is_active_datatype }})
            AND ldts.min_ldts IS NOT NULL

        ),
    {% endif %}
{%- endif %}

records_to_insert AS (

    {#
        This first part of the UNION includes:
            - for single-batch loads: Only is_active_alias = true, deactivations are handled later
            - for multi-batch loads: Ativation and deactivation inside the multiple loads
    #}
    SELECT
        di.{{ tracked_hashkey }},
        {% for col in additional_columns -%}
        di.{{ col }},
        {% endfor -%}
        di.{{ src_ldts }},
        di.{{ src_rsrc }},
        di.{{ is_active_alias }}
    FROM {{ ns.last_cte }} di


    {%- if is_incremental() %}

        {#
            For incremental multi-batch loads, the earliest to-be inserted status is compared to the current status. 
            It will only be inserted if the status changed.
        #} 
        {%- if not source_is_single_batch %}
            WHERE NOT EXISTS (
                SELECT 1
                FROM current_status
                WHERE {{ datavault4dbt.multikey(tracked_hashkey, prefix=['current_status', 'di'], condition='=') }}
                    AND cast(di.{{ is_active_alias }} as {{ is_active_datatype }}) = current_status.{{ is_active_alias }}
                    AND di.{{ src_ldts }} = (SELECT MIN({{ src_ldts }}) FROM deduplicated_incoming)
                )
            AND di.{{ src_ldts }} > (SELECT MAX({{ src_ldts }}) FROM {{ this }})
        {% endif %}

    {#
        For all incremental loads, the disappeared hashkeys are UNIONed.
    #}
    UNION

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ src_ldts }},
        {{ src_rsrc }},
        {{ is_active_alias }}
    FROM disappeared_hashkeys

    {%- endif %}

)

SELECT 
    {{ tracked_hashkey }},
    {% for col in additional_columns -%}
    {{ col }},
    {% endfor -%}
    {{ src_ldts }},
    {{ src_rsrc }},
    cast({{ is_active_alias }} as {{ is_active_datatype }}) as {{ is_active_alias }}
FROM records_to_insert ri

{% if is_incremental() %}
WHERE NOT EXISTS (
    SELECT 1
    FROM {{ this }} t
    WHERE t.{{ tracked_hashkey }} = ri.{{ tracked_hashkey }}
        AND t.{{ src_ldts }} = ri.{{ src_ldts }}
)
{% endif %}

{%- endmacro -%}

macro.datavault4dbt.databricks__hub.macro_sql:
{%- macro databricks__hub(hashkey, business_keys, src_ldts, src_rsrc, source_models, disable_hwm, additional_columns) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{{ log('source_models'~source_models, false) }}

{%- set ns = namespace(last_cte= "", source_included_before = {}, has_rsrc_static_defined=true, source_models_rsrc_dict={}) -%}

{# Select the Business Key column from the first source model definition provided in the hub model and put them in an array. #}
{%- set business_keys = datavault4dbt.expand_column_list(columns=[business_keys]) -%}

{# Select the additional_columns from the hub model and put them in an array. If additional_colums none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{# If no specific bk_columns is defined for each source, we apply the values set in the business_keys variable. #}
{# If no specific hk_column is defined for each source, we apply the values set in the hashkey variable. #}
{# If no rsrc_static parameter is defined in ANY of the source models then the whole code block of record_source performance lookup is not executed  #}
{# For the use of record_source performance lookup it is required that every source model has the parameter rsrc_static defined and it cannot be an empty string #}
{%- if source_models is not mapping and not datavault4dbt.is_list(source_models) -%}
    {%- set source_models = {source_models: {}} -%}
{%- endif -%}

{%- set source_model_values = fromjson(datavault4dbt.source_model_processing(source_models=source_models, parameters={'hk_column':hashkey}, business_keys=business_keys)) -%}
{%- set source_models = source_model_values['source_model_list'] -%}
{%- set ns.has_rsrc_static_defined = source_model_values['has_rsrc_static_defined'] -%}
{%- set ns.source_models_rsrc_dict = source_model_values['source_models_rsrc_dict'] -%}
{{ log('source_models: '~source_models, false) }}

{%- set final_columns_to_select = [hashkey] + business_keys + [src_ldts] + [src_rsrc] + additional_columns -%}
{%- set final_columns_to_select = datavault4dbt.escape_column_names(final_columns_to_select) -%}

{%- set hashkey = datavault4dbt.escape_column_names(hashkey) -%}
{%- set business_keys = datavault4dbt.escape_column_names(business_keys) -%}
{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}
{%- set additional_columns = datavault4dbt.escape_column_names(additional_columns) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{% if is_incremental() -%}
    {%- if ns.has_rsrc_static_defined and not disable_hwm -%}
        {% for source_model in source_models %}
         {# Create a query with a rsrc_static column with each rsrc_static for each source model. #}
            {%- set source_number = source_model.id | string -%}
            {%- set rsrc_statics = ns.source_models_rsrc_dict[source_number] -%}

            {{ log('rsrc_statics: '~ rsrc_statics, false) }}

            {%- set rsrc_static_query_source -%}
                SELECT count(*) FROM (
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT t.{{ src_rsrc }},
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }} t
                    WHERE {{ src_rsrc }} like '{{ rsrc_static }}'
                    {%- if not loop.last %}
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
                )
            {% endset %}

            {{ log('rsrc static query: '~rsrc_static_query_source, false) }}

            rsrc_static_{{ source_number }} AS (
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT 
                    t.*,
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }} t
                    WHERE {{ src_rsrc }} like '{{ rsrc_static }}'
                    {%- if not loop.last %}
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
                {%- set ns.last_cte = "rsrc_static_{}".format(source_number) -%}
            ),
            
            {%- set source_in_target = true -%}
            
            {%- if execute -%}
                {%- set rsrc_static_result = run_query(rsrc_static_query_source) -%}

                {%- set row_count = rsrc_static_result.columns[0].values()[0] -%}

                {{ log('row_count for '~source_model~' is '~row_count, false) }}

                {%- if row_count == 0 -%}
                    {%- set source_in_target = false -%}
                {%- endif -%}
            {%- endif -%}


            {%- do ns.source_included_before.update({source_model.id: source_in_target}) -%}

        {% endfor -%}

        {%- if source_models | length > 1 %}

        rsrc_static_union AS (
            {#  Create one unionized table over all sources. It will be the same as the already existing
                hub, but extended by the rsrc_static column. #}
            {% for source_model in source_models %}
            {%- set source_number = source_model.id | string -%}

            SELECT rsrc_static_{{ source_number }}.* FROM rsrc_static_{{ source_number }}

            {%- if not loop.last %}
            UNION ALL
            {% endif -%}
            {%- endfor %}
            {%- set ns.last_cte = "rsrc_static_union" -%}
        ),

        {%- endif %}

        max_ldts_per_rsrc_static_in_target AS (
        {# Use the previously created CTE to calculate the max load date timestamp per rsrc_static. #}
            SELECT
                rsrc_static,
                MAX({{ src_ldts }}) as max_ldts
            FROM {{ ns.last_cte }}
            WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
            GROUP BY rsrc_static

        ),
    {%- endif %}
{% endif -%}

{% for source_model in source_models %}

    {%- set source_number = source_model.id | string -%}

    {%- if ns.has_rsrc_static_defined -%}
        {%- set rsrc_statics = ns.source_models_rsrc_dict[source_number|string] -%}
    {%- endif -%}

