        {%- else -%}
            {%- set all_sat_columns = datavault4dbt.source_columns(ref(satellite)) | map('lower') -%}
            {%- set sat_columns_pre = datavault4dbt.process_columns_to_select(all_sat_columns, sat_columns_to_exclude | map('lower')) -%}
        {%- endif -%}

    {%- set sat_columns = datavault4dbt.process_columns_to_select(sat_columns_pre, sat_columns_to_exclude | map('lower')) -%}
    {%- set sat_columns = datavault4dbt.escape_column_names(sat_columns) -%}

    {{- log('sat_columns: '~ sat_columns, false) -}}

    {{ datavault4dbt.print_list(list_to_print=sat_columns, indent=2, src_alias=sat_alias) }}
    {%- if not loop.last -%} ,
    {% endif -%}

    {% endfor %} 

    FROM {{ ref(ref_hub) }} h
    
    FULL OUTER JOIN dates ld
        ON 1 = 1  

    {% for satellite in ref_satellites_dict.keys() %}

        {%- set sat_alias = 's_' + loop.index|string -%}

    LEFT JOIN {{ ref(satellite) }} {{ sat_alias }}
        ON {{ datavault4dbt.multikey(columns=datavault4dbt.escape_column_names(ref_key_cols), prefix=['h', sat_alias], condition='=') }}
        AND  ld.{{ date_column }} BETWEEN {{ sat_alias }}.{{ src_ldts }} AND {{ sat_alias }}.{{ ledts_alias }}
    
    {% endfor %}
    
    {% if include_business_objects_before_appearance == 'false' -%}
    WHERE h.{{ src_ldts }} <= ld.{{ date_column }}
    {% endif %}

) 

SELECT * FROM ref_table

{%- endmacro -%}

macro.datavault4dbt.databricks__sat_v0.macro_sql:
{%- macro databricks__sat_v0(parent_hashkey, src_hashdiff, src_payload, src_ldts, src_rsrc, source_model, disable_hwm, source_is_single_batch, additional_columns) -%}

{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ns=namespace(src_hashdiff="", hdiff_alias="") %}

{%- if  src_hashdiff is mapping and src_hashdiff is not none -%}
    {% set ns.src_hashdiff = src_hashdiff["source_column"] %}
    {% set ns.hdiff_alias = src_hashdiff["alias"] %}
{% else %}
    {% set ns.src_hashdiff = src_hashdiff %}
    {% set ns.hdiff_alias = src_hashdiff  %}
{%- endif -%}

{# Select the additional_columns and put them in an array. If additional_colums none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set source_cols = datavault4dbt.expand_column_list(columns=[src_rsrc, src_ldts, src_payload, additional_columns]) -%}

{%- set source_relation = ref(source_model) -%}

{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}
{%- set parent_hashkey = datavault4dbt.escape_column_names(parent_hashkey) -%}
{%- set src_hashdiff = datavault4dbt.escape_column_names(src_hashdiff) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Selecting all source data, that is newer than latest data in sat if incremental #}
source_data AS (

    SELECT
        {{ parent_hashkey }},
        {{ ns.src_hashdiff }} as {{ ns.hdiff_alias }},
        {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ source_relation }}

    {%- if is_incremental() %}
    WHERE {{ src_ldts }} > (
        SELECT
            MAX({{ src_ldts }}) FROM {{ this }}
        WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    )
    {%- endif %}
),

{# Get the latest record for each parent hashkey in existing sat, if incremental. #}
{%- if is_incremental() %}
latest_entries_in_sat AS (

    SELECT
        {{ parent_hashkey }},
        {{ ns.hdiff_alias }}
    FROM 
        {{ this }}
    WHERE 1=1
    
    {{ datavault4dbt.filter_latest_entries_in_sat() }}

    QUALIFY ROW_NUMBER() OVER(PARTITION BY {{ parent_hashkey|lower }} ORDER BY {{ src_ldts }} DESC) = 1  
),
{%- endif %}

{#
    Deduplicate source by comparing each hashdiff to the hashdiff of the previous record, for each hashkey.
    Additionally adding a row number based on that order, if incremental.
#}
deduplicated_numbered_source AS (

    SELECT
    {{ parent_hashkey }},
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    {% if is_incremental() -%}
    , ROW_NUMBER() OVER(PARTITION BY {{ parent_hashkey }} ORDER BY {{ src_ldts }}) as rn
    {%- endif %}
    FROM source_data
    QUALIFY
        CASE
            WHEN {{ ns.hdiff_alias }} = LAG({{ ns.hdiff_alias }}) OVER(PARTITION BY {{ parent_hashkey|lower }} ORDER BY {{ src_ldts }}) THEN FALSE
            ELSE TRUE
        END
),

{#
    Select all records from the previous CTE. If incremental, compare the oldest incoming entry to
    the existing records in the satellite.
#}
records_to_insert AS (

    SELECT
    {{ parent_hashkey }},
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    FROM deduplicated_numbered_source
    {%- if is_incremental() %}
    WHERE NOT EXISTS (
        SELECT 1
        FROM latest_entries_in_sat
        WHERE {{ datavault4dbt.multikey(parent_hashkey, prefix=['latest_entries_in_sat', 'deduplicated_numbered_source'], condition='=') }}
            AND {{ datavault4dbt.multikey(ns.hdiff_alias, prefix=['latest_entries_in_sat', 'deduplicated_numbered_source'], condition='=') }}
            AND deduplicated_numbered_source.rn = 1)
    {%- endif %}

    )

SELECT * FROM records_to_insert

{%- endmacro -%}

macro.datavault4dbt.databricks__sat_v1.macro_sql:
{%- macro databricks__sat_v1(sat_v0, hashkey, hashdiff, src_ldts, src_rsrc, ledts_alias, add_is_current_flag, include_payload) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set is_current_col_alias = var('datavault4dbt.is_current_col_alias', 'IS_CURRENT') -%}
{%- set is_current_col_alias = datavault4dbt.escape_column_names(is_current_col_alias) -%}

{%- set source_relation = ref(sat_v0) -%}

{%- set all_columns = datavault4dbt.source_columns(source_relation=source_relation) -%}
{%- set exclude = [hashkey, hashdiff, src_ldts, src_rsrc] -%}

{%- set source_columns_to_select = datavault4dbt.process_columns_to_select(all_columns, exclude) -%}
{%- set source_columns_to_select = datavault4dbt.escape_column_names(source_columns_to_select) -%}

{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}
{%- set ledts_alias = datavault4dbt.escape_column_names(ledts_alias) -%}
{%- set hashkey = datavault4dbt.escape_column_names(hashkey) -%}
{%- set hashdiff = datavault4dbt.escape_column_names(hashdiff) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Calculate ledts based on the ldts of the earlier record. #}
end_dated_source AS (

    SELECT
        {{ hashkey }},
        {{ hashdiff }},
        {{ src_rsrc }},
        {{ src_ldts }},
        COALESCE(LEAD(TRY_SUBTRACT({{ src_ldts }}, INTERVAL 1 MICROSECOND)) OVER (PARTITION BY {{ hashkey }} ORDER BY {{ src_ldts }}),{{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}) as {{ ledts_alias }}
        {%- if include_payload -%},
            {{ datavault4dbt.print_list(source_columns_to_select) }}
        {%- endif %}
    FROM {{ source_relation }}

)

SELECT
    {{ hashkey }},
    {{ hashdiff }},
    {{ src_rsrc }},
    {{ src_ldts }},
    {{ ledts_alias }}
    {%- if add_is_current_flag %},
        CASE WHEN {{ ledts_alias }} = {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
        THEN TRUE
        ELSE FALSE
        END AS {{ is_current_col_alias }}
    {% endif -%}
    {%- if include_payload -%},
        {{ datavault4dbt.print_list(source_columns_to_select) }}
    {%- endif %}
FROM end_dated_source

{%- endmacro -%}

macro.datavault4dbt.exasol__control_snap.macro_sql:
{%- macro exasol__control_snap_v1(control_snap_v0, log_logic, sdts_alias) -%}

{# sample log_logic 
   {%-set log_logic = {'daily': {'duration': 3,
                                'unit': 'MONTH',
                                'forever': 'FALSE'},
                      'monthly': {'duration': 5,
                                  'unit': 'YEAR'},
                      'yearly': {'duration': 10,
                                'unit': 'YEAR'} } %} 

#}

{%- if log_logic is not none %}
    {%- for interval in log_logic.keys() %}
        {%- if 'forever' not in log_logic[interval].keys() -%}
            {% do log_logic[interval].update({'forever': 'FALSE'}) %}
        {%- endif -%}
    {%- endfor -%}
{%- endif %}

{%- set v0_relation = ref(control_snap_v0) -%}
{%- set ns = namespace(forever_status=FALSE) %}

{%- set snapshot_trigger_column = var('datavault4dbt.snapshot_trigger_column', 'is_active') -%}

WITH

latest_row AS (

    SELECT
        {{ sdts_alias }}
    FROM {{ v0_relation }}
    ORDER BY {{ sdts_alias }} DESC
    LIMIT 1

),

virtual_logic AS (

    SELECT
        c.{{ sdts_alias }},
        c.replacement_sdts,
        c.force_active,
        {%- if log_logic is none %}
        TRUE as {{ snapshot_trigger_column }},
        {%- else %}
        CASE 
            WHEN
            {% if 'daily' in log_logic.keys() %}
                {%- if log_logic['daily']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' -%}
                    (1=1)
                {%- else %}
                    {%- set daily_duration = log_logic['daily']['duration'] -%}
                    {%- set daily_unit = log_logic['daily']['unit'] -%}
                  (DATE_TRUNC('DAY', TO_DATE(c.{{ sdts_alias }})) BETWEEN ADD_{{ daily_unit}}S(CURRENT_DATE, -{{ daily_duration }}) AND CURRENT_DATE)
                {%- endif -%}   
            {%- endif %}

            {%- if 'weekly' in log_logic.keys() %}
            OR
                {%- if log_logic['weekly']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' -%}
                    (c.is_weekly = TRUE)
                {%- else %}
                    {%- set weekly_duration = log_logic['weekly']['duration'] -%}
                    {%- set weekly_unit = log_logic['weekly']['unit'] -%}
                    ((DATE_TRUNC('DAY', TO_DATE(c.{{ sdts_alias }})) BETWEEN ADD_{{ weekly_unit}}S(CURRENT_DATE, -{{ weekly_duration }}) AND CURRENT_DATE)
                    AND
                    (c.is_weekly = TRUE))
                {%- endif -%}
            {% endif -%}

            {%- if 'monthly' in log_logic.keys() %}
            OR
                {%- if log_logic['monthly']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' %}
              (c.is_monthly = TRUE)
                {%- else %}
                    {%- set monthly_duration = log_logic['monthly']['duration'] -%}
                    {%- set monthly_unit = log_logic['monthly']['unit'] %}

                    ((DATE_TRUNC('DAY', TO_DATE(c.{{ sdts_alias }})) BETWEEN ADD_{{ monthly_unit }}S(CURRENT_DATE, -{{ monthly_duration }}) AND CURRENT_DATE) 
                    AND 
                    (c.is_monthly = TRUE))
                {%- endif -%}
            {% endif -%}

            {%- if 'yearly' in log_logic.keys() %}
            OR
                {%- if log_logic['yearly']['forever'] is true -%}
                    {%- set ns.forever_status = 'TRUE' -%}
                    (c.is_yearly = TRUE)
                {%- else %}
                    {%- set yearly_duration = log_logic['yearly']['duration'] -%}
                    {%- set yearly_unit = log_logic['yearly']['unit'] %}

                    ((DATE_TRUNC('DAY', TO_DATE(c.{{ sdts_alias }})) BETWEEN ADD_{{ yearly_unit }}S(CURRENT_DATE, - {{ yearly_duration }}) AND CURRENT_DATE) 
                    AND 
                    (c.is_yearly = TRUE))
                {%- endif -%}
            {% endif %}
            THEN TRUE
            ELSE FALSE

        END AS {{ snapshot_trigger_column }},
        {%- endif %}
        CASE
            WHEN l.{{ sdts_alias }} IS NULL THEN FALSE
            ELSE TRUE
        END AS is_latest,

        c.caption,
        c.is_hourly,
        c.is_daily,
        c.is_weekly,
        c.is_monthly,
        c.is_yearly,
        CASE
            WHEN EXTRACT(YEAR FROM c.{{ sdts_alias }}) = EXTRACT(YEAR FROM CURRENT_DATE) THEN TRUE
            ELSE FALSE
        END AS is_current_year,
        CASE
            WHEN EXTRACT(YEAR FROM c.{{ sdts_alias }}) = EXTRACT(YEAR FROM CURRENT_DATE)-1 THEN TRUE
            ELSE FALSE
        END AS is_last_year,
        CASE
            WHEN DATE_TRUNC('DAY', TO_DATE(c.{{ sdts_alias }})) BETWEEN ADD_YEARS(CURRENT_DATE,-1) AND CURRENT_DATE THEN TRUE
            ELSE FALSE
        END AS is_rolling_year,
        CASE
            WHEN DATE_TRUNC('DAY', TO_DATE(c.{{ sdts_alias }})) BETWEEN ADD_YEARS(CURRENT_DATE,-2) AND ADD_YEARS(CURRENT_DATE,-1) THEN TRUE
            ELSE FALSE
        END AS is_last_rolling_year,
        c.comment
    FROM {{ v0_relation }} c
    LEFT JOIN latest_row l
        ON c.{{ sdts_alias }} = l.{{ sdts_alias }}

),

active_logic_combined AS (

    SELECT 
        {{ sdts_alias }},
        replacement_sdts,
        CASE
            WHEN force_active AND {{ snapshot_trigger_column }} THEN TRUE
            WHEN NOT force_active OR NOT {{ snapshot_trigger_column }} THEN FALSE
        END AS {{ snapshot_trigger_column }},
        is_latest, 
        caption,
        is_hourly,
        is_daily,
        is_weekly,
        is_monthly,
        is_yearly,
        is_current_year,
        is_last_year,
        is_rolling_year,
        is_last_rolling_year,
        comment
    FROM virtual_logic

)

SELECT * FROM active_logic_combined

{%- endmacro -%}

macro.datavault4dbt.exasol__eff_sat_v0.macro_sql:
{%- macro exasol__eff_sat_v0(source_model, tracked_hashkey, src_ldts, src_rsrc, is_active_alias, source_is_single_batch, disable_hwm, additional_columns) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ns = namespace(last_cte= "") -%}

{%- set source_relation = ref(source_model) -%}

{# Select the additional_columns and put them in an array. If additional_colums is none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set tracked_hashkey = datavault4dbt.escape_column_names(tracked_hashkey) -%}
{%- set is_active_alias = datavault4dbt.escape_column_names(is_active_alias) -%}
{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}

{%- set unknown_value_rsrc = var('datavault4dbt.default_unknown_rsrc', 'SYSTEM') -%}

{%- set is_active_datatype = var('datavault4dbt.is_active_datatype', 'Boolean') -%}

{{ datavault4dbt.prepend_generated_by() }}


WITH

{#
    In all cases, the source model is selected, and optionally a HWM is applied. 
#}
source_data AS (

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ src_ldts }},
        {{ src_rsrc }}
    FROM {{ source_relation }} src
    WHERE {{ src_ldts }} NOT IN ({{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}, {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }})
    {%- if is_incremental() and not disable_hwm %}
    AND src.{{ src_ldts }} > (
        SELECT
            MAX({{ src_ldts }})
        FROM {{ this }}
        WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    )
    {%- endif %}
),

{#
    In all incremental cases, the current status for each hashkey is selected from the existing Effectivity Satellite.
#}
{%- if is_incremental() %}
current_status AS (

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ is_active_alias }},
        {{ src_rsrc }}
    FROM {{ this }}
    QUALIFY 
        ROW_NUMBER() OVER(PARTITION BY {{ tracked_hashkey }} ORDER BY {{ src_ldts }} DESC) = 1

),
{% endif %}

{#
    This block is for multi-batch processing. 
#}
{% if not source_is_single_batch %}

    {#
        List of all Hashkeys with their date of first appearance in the source model.
    #}
    hashkeys AS (

        SELECT 
            {{ tracked_hashkey }},
            MIN({{ src_ldts }}) as first_appearance
        FROM source_data
        GROUP BY {{ tracked_hashkey }}

    ),

    {#
        Distinct list of load dates in the multi-batch source.
    #}
    load_dates AS (

        SELECT Distinct
            {{ src_ldts }}
        FROM source_data
        
    ),

    {#
        All combinations of hashkeys and loaddates, for loaddates after the first appearance of a hashkey.
    #}
    history AS (

        SELECT 
            hk.{{ tracked_hashkey }},
            ld.{{ src_ldts }}
        FROM hashkeys hk
        CROSS JOIN load_dates ld
        WHERE ld.{{ src_ldts }} >= hk.first_appearance

    ),

    {#
        All theoretical combinations are checked against the actual occurences of hashkeys in each batch / loaddate.
        If a Hashkey is part of a load/batch, is_active_alias is set to true, because the hashkey was active in that load/batch.
        If a Hashkey is not part of a load/batch, is_active_alias is set to false, because the hashkey was not active in that load/batch.
    #}
    is_active AS (

        SELECT
            h.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            src.{{ col }},
            {% endfor -%}
            h.{{ src_ldts }},
            COALESCE(src.{{ src_rsrc }}, '{{ unknown_value_rsrc }}') AS {{ src_rsrc }},
            CASE 
                WHEN src.{{ tracked_hashkey }} IS NULL THEN 0
                ELSE 1 
            END as {{ is_active_alias }}
        FROM history h
        LEFT JOIN source_data src
            ON src.{{ tracked_hashkey }} = h.{{ tracked_hashkey }}
            AND src.{{ src_ldts }} = h.{{ src_ldts }}

    ),

    {#
        The rows are deduplicated on the is_active_alias, to only include status changes. 
    #}
    deduplicated_incoming AS (

        SELECT
            is_active.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            is_active.{{ col }},
            {% endfor -%}
            is_active.{{ src_ldts }},
            is_active.{{ src_rsrc }},
            is_active.{{ is_active_alias }}
        FROM is_active
        QUALIFY 
            CASE 
                WHEN is_active.{{ is_active_alias }} = LAG(is_active.{{ is_active_alias }}) OVER (PARTITION BY {{ tracked_hashkey }} ORDER BY {{ src_ldts }}) THEN FALSE
                ELSE TRUE
            END

    ),

    {% set ns.last_cte = 'deduplicated_incoming' %}

{#
    This block is for single-batch processing
#}
{% else %}

    {#
        In initial loads of single-batch eff sats, every hashkey of the source is set to active.
    #}
    new_hashkeys AS (

        SELECT DISTINCT
            src.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            src.{{ col }},
            {% endfor -%}
            src.{{ src_ldts }},
            src.{{ src_rsrc }},
            1 as {{ is_active_alias }}
        FROM source_data src

        {#
            For incremental runs of single-batch eff sats, only hashkeys that are not active right now are set to active. 
            This automatically includes totally new hashkeys, or hashkeys that are currently set to inactive.
        #}
        {% if is_incremental() %}
            LEFT JOIN current_status cus
                ON src.{{ tracked_hashkey }} = cus.{{ tracked_hashkey }}
                AND cus.{{ is_active_alias }} = cast(1 as {{ is_active_datatype }})
            WHERE cus.{{ tracked_hashkey }} IS NULL
        {% endif %}

    ),

    {% set ns.last_cte = 'new_hashkeys' %}

{% endif %}

{#
    In all incremental runs, the source needs to be scanned for all currently active hashkeys. 
    If they are no longer present, they will be deactived. 
#}
{%- if is_incremental() %}

    {%- if not source_is_single_batch %}
        disappeared_hashkeys AS (

            SELECT DISTINCT 
                cus.{{ tracked_hashkey }},
                {% for col in additional_columns -%}
                null as {{ col }},
                {% endfor -%}
                ldts.min_ldts as {{ src_ldts }},
                '{{unknown_value_rsrc}}' AS {{ src_rsrc }},
                0 as {{ is_active_alias }}
            FROM current_status cus
            LEFT JOIN (
                SELECT 
                    MIN({{ src_ldts }}) as min_ldts
                FROM deduplicated_incoming) ldts
                ON 1 = 1
            LEFT JOIN deduplicated_incoming src
                ON src.{{ tracked_hashkey }} = cus.{{ tracked_hashkey }}
                AND  src.{{ src_ldts }} = ldts.min_ldts
            WHERE
                cus.{{ is_active_alias }} = cast(1 as {{ is_active_datatype }})
                AND src.{{ tracked_hashkey }} IS NULL
                AND ldts.min_ldts IS NOT NULL

        ),
    {% else %}
        disappeared_hashkeys AS (

            SELECT DISTINCT 
                cus.{{ tracked_hashkey }},
                {% for col in additional_columns -%}
                null as {{ col }},
                {% endfor -%}
                ldts.min_ldts as {{ src_ldts }},
                '{{unknown_value_rsrc}}' AS {{ src_rsrc }},
                0 as {{ is_active_alias }}
            FROM current_status cus
            LEFT JOIN (
                SELECT 
                    MIN({{ src_ldts }}) as min_ldts
                FROM source_data) ldts
                ON 1 = 1
            WHERE NOT EXISTS (
                SELECT 
                    1 
                FROM source_data src
                WHERE src.{{ tracked_hashkey }} = cus.{{ tracked_hashkey }}
            )
            AND cus.{{ is_active_alias }} = cast(1 as {{ is_active_datatype }})
            AND ldts.min_ldts IS NOT NULL

        ),
    {% endif %}
{%- endif %}

records_to_insert AS (

    {#
        This first part of the UNION includes:
            - for single-batch loads: Only is_active_alias = true, deactivations are handled later
            - for multi-batch loads: Ativation and deactivation inside the multiple loads
    #}
    SELECT
        di.{{ tracked_hashkey }},
        {% for col in additional_columns -%}
        di.{{ col }},
        {% endfor -%}
        di.{{ src_ldts }},
        di.{{ src_rsrc }},
        di.{{ is_active_alias }}
    FROM {{ ns.last_cte }} di


    {%- if is_incremental() %}

        {#
            For incremental multi-batch loads, the earliest to-be inserted status is compared to the current status. 
            It will only be inserted if the status changed.
        #} 
        {%- if not source_is_single_batch %}
            WHERE NOT EXISTS (
                SELECT 1
                FROM current_status
                WHERE {{ datavault4dbt.multikey(tracked_hashkey, prefix=['current_status', 'di'], condition='=') }}
                    AND cast(di.{{ is_active_alias }} as {{ is_active_datatype }}) = current_status.{{ is_active_alias }}
                    AND di.{{ src_ldts }} = (SELECT MIN({{ src_ldts }}) FROM deduplicated_incoming)
                )
            AND di.{{ src_ldts }} > (SELECT MAX({{ src_ldts }}) FROM {{ this }})
        {% endif %}

    {#
        For all incremental loads, the disappeared hashkeys are UNIONed.
    #}
    UNION

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ src_ldts }},
        {{ src_rsrc }},
        {{ is_active_alias }}
    FROM disappeared_hashkeys

    {%- endif %}

)

SELECT 
    {{ tracked_hashkey }},
    {% for col in additional_columns -%}
