{%- endif %}

{%- if is_incremental() -%}
    WHERE {{ date_column }} > (SELECT MAX({{ date_column }}) FROM {{ this }})
{%- endif -%}


),

ref_table AS (

    SELECT
    {{ datavault4dbt.print_list(list_to_print=ref_key_cols, indent=2, src_alias='h') }},
        ld.{{ date_column }},
