    WHERE h.{{ src_ldts }} <= ld.{{ date_column }}
    {% endif %}

) 

SELECT * FROM ref_table

{%- endmacro -%}

macro.datavault4dbt.exasol__sat_v0.macro_sql:
{%- macro exasol__sat_v0(parent_hashkey, src_hashdiff, src_payload, src_ldts, src_rsrc, source_model, disable_hwm, source_is_single_batch, additional_columns) -%}

{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ns=namespace(src_hashdiff="", hdiff_alias="") %}

{%- if  src_hashdiff is mapping and src_hashdiff is not none -%}
    {% set ns.src_hashdiff = src_hashdiff["source_column"] %}
    {% set ns.hdiff_alias = src_hashdiff["alias"] %}
{% else %}
    {% set ns.src_hashdiff = src_hashdiff %}
    {% set ns.hdiff_alias = src_hashdiff  %}
{%- endif -%}

{# Select the additional_columns and put them in an array. If additional_colums none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set source_cols = datavault4dbt.expand_column_list(columns=[src_rsrc, src_ldts, src_payload, additional_columns]) -%}

{%- set source_relation = ref(source_model) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Selecting all source data, that is newer than latest data in sat if incremental #}
source_data AS (

    SELECT
        {{ parent_hashkey }},
        {{ ns.src_hashdiff }} as {{ ns.hdiff_alias }},
        {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ source_relation }}

    {%- if is_incremental() %}
    WHERE {{ src_ldts }} > (
        SELECT
            MAX({{ src_ldts }}) FROM {{ this }}
        WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    )
    {%- endif %}
),

{# Get the latest record for each parent hashkey in existing sat, if incremental. #}
{%- if is_incremental() %}
latest_entries_in_sat AS (

    SELECT
        {{ parent_hashkey }},
        {{ ns.hdiff_alias }}
    FROM 
        {{ this }}
     WHERE 1=1
        
    {{ datavault4dbt.filter_latest_entries_in_sat() }}

    QUALIFY ROW_NUMBER() OVER(PARTITION BY {{ parent_hashkey|lower }} ORDER BY {{ src_ldts }} DESC) = 1  
),
{%- endif %}

{#
    Deduplicate source by comparing each hashdiff to the hashdiff of the previous record, for each hashkey.
    Additionally adding a row number based on that order, if incremental.
#}
deduplicated_numbered_source AS (

    SELECT
    {{ parent_hashkey }},
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    {% if is_incremental() -%}
     , ROW_NUMBER() OVER(PARTITION BY {{ parent_hashkey }} ORDER BY {{ src_ldts }}) as rn
    {%- endif %}
    FROM source_data
    QUALIFY
        CASE
            WHEN {{ ns.hdiff_alias }} = LAG({{ ns.hdiff_alias }}) OVER(PARTITION BY {{ parent_hashkey|lower }} ORDER BY {{ src_ldts }}) THEN FALSE
            ELSE TRUE
        END
),

{#
    Select all records from the previous CTE. If incremental, compare the oldest incoming entry to
    the existing records in the satellite.
#}
records_to_insert AS (

    SELECT
    {{ parent_hashkey }},
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    FROM deduplicated_numbered_source
    {%- if is_incremental() %}
    WHERE NOT EXISTS (
        SELECT 1
        FROM latest_entries_in_sat
        WHERE {{ datavault4dbt.multikey(parent_hashkey, prefix=['latest_entries_in_sat', 'deduplicated_numbered_source'], condition='=') }}
            AND {{ datavault4dbt.multikey(ns.hdiff_alias, prefix=['latest_entries_in_sat', 'deduplicated_numbered_source'], condition='=') }}
            AND deduplicated_numbered_source.rn = 1)
    {%- endif %}

    )

SELECT * FROM records_to_insert

{%- endmacro -%}

macro.datavault4dbt.exasol__sat_v1.macro_sql:
{%- macro exasol__sat_v1(sat_v0, hashkey, hashdiff, src_ldts, src_rsrc, ledts_alias, add_is_current_flag, include_payload) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set is_current_col_alias = var('datavault4dbt.is_current_col_alias', 'IS_CURRENT') -%}

{%- set source_relation = ref(sat_v0) -%}

{%- set all_columns = datavault4dbt.source_columns(source_relation=source_relation) -%}
{%- set exclude = [hashkey, hashdiff, src_ldts, src_rsrc] -%}

{%- set source_columns_to_select = datavault4dbt.process_columns_to_select(all_columns, exclude) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Calculate ledts based on the ldts of the earlier record. #}
end_dated_source AS (

    SELECT
        {{ hashkey }},
        {{ hashdiff }},
        {{ src_rsrc }},
        {{ src_ldts }},
        COALESCE(LEAD(ADD_SECONDS({{ src_ldts }}, -0.001)) OVER (PARTITION BY {{ hashkey }} ORDER BY {{ src_ldts }}),{{ datavault4dbt.string_to_timestamp( timestamp_format , end_of_all_times) }}) as {{ ledts_alias }}
        {%- if include_payload -%},
            {{ datavault4dbt.print_list(source_columns_to_select) }}
        {%- endif %}
    FROM {{ source_relation }}

)

SELECT
    {{ hashkey }},
    {{ hashdiff }},
    {{ src_rsrc }},
    {{ src_ldts }},
    {{ ledts_alias }}
    {%- if add_is_current_flag %},
        CASE WHEN {{ ledts_alias }} = {{ datavault4dbt.string_to_timestamp( timestamp_format , end_of_all_times) }}
        THEN TRUE
        ELSE FALSE
        END AS {{ is_current_col_alias }}
    {% endif -%}
    {%- if include_payload -%},
        {{ datavault4dbt.print_list(source_columns_to_select) }}
    {%- endif %}
FROM end_dated_source

{%- endmacro -%}

macro.datavault4dbt.fabric__control_snap.macro_sql:
{%- macro fabric__control_snap_v1(control_snap_v0, log_logic, sdts_alias) -%}

{%- set snapshot_trigger_column = var('datavault4dbt.snapshot_trigger_column', 'is_active') -%}

{%- set ns = namespace(forever_status_dict={}, log_logic_list=[], col_name='', log_logic={}) %}



{%- if log_logic is not none %}

{{ log('log_logic: ' ~ log_logic, false) }}

	{%- if log_logic is mapping -%}

		{%- for interval in log_logic.keys() %}
			{%- if 'forever' not in log_logic[interval].keys() -%}
				{% do log_logic[interval].update({'forever': 'FALSE'}) %}
			{%- endif -%}
		{%- endfor -%}

		{%- do ns.log_logic_list.append({snapshot_trigger_column: log_logic}) -%}
		{%- do ns.forever_status_dict.update({snapshot_trigger_column: 'FALSE'}) -%}

	{%- elif datavault4dbt.is_list(log_logic) -%}

		{%- for logic in log_logic -%}

			{{ log('logic: ' ~ logic, false) }}
			{% for col_name, logic_definition in logic.items() -%}
				{{ log('logic_definition: ' ~ logic_definition, false) }}
				{{ log('col_name: ' ~ col_name, false) }}
				{%- set ns.col_name = col_name -%}
				{%- set ns.logic_definition = logic_definition %}
			{%- endfor -%}

			{%- for interval in ns.logic_definition.keys() %}
				{%- if 'forever' not in ns.logic_definition[interval].keys() -%}
					{% do ns.logic_definition[interval].update({'forever': 'FALSE'}) %}
				{%- endif -%}
			{%- endfor -%}

			{%- do ns.log_logic_list.append({ns.col_name: ns.logic_definition}) -%}
			{%- do ns.forever_status_dict.update({ns.col_name: 'FALSE'}) -%}

		{%- endfor -%}

	{%- else -%}

		{{ exceptions.raise_compiler_error("Invalid format of log_logic definition in Snapshot Control v1. Either one Dictionary with the config, or a list of dictionaries with the name of the output col as a key, and the log config as each value.")}}

	{%- endif -%}

{%- endif %}

{%- set v0_relation = ref(control_snap_v0) -%}


WITH in_the_past as (

SELECT 
	*,
	ROW_NUMBER() OVER (ORDER BY {{ sdts_alias }} desc) as rn

FROM {{ ref(control_snap_v0) }}
WHERE CONVERT(DATE, {{ sdts_alias }}) <= CONVERT(DATE, GETDATE() )
),

dynamic as (SELECT 
	src.{{ sdts_alias }},
	src.{{ sdts_alias }}_date,
	src.force_active,
	{# CASE WHEN itp.{{ sdts_alias }} is not null THEN 1 ELSE 0 END AS is_in_the_past, #}
	CASE WHEN itp.rn = 1 THEN 1 ELSE 0 END AS is_latest, 
	CASE WHEN DATEPART(YEAR, src.{{ sdts_alias }}) = DATEPART(YEAR, GETDATE()) THEN 1 ELSE 0 END as is_current_year, 
	CASE WHEN DATEPART(YEAR, src.{{ sdts_alias }}) = DATEPART(YEAR, GETDATE())-1 THEN 1 ELSE 0 END as is_last_year, 
	CASE WHEN DATEDIFF(day, src.{{ sdts_alias }}, GETDATE()) between 0 and 365 THEN 1 ELSE 0 END as is_rolling_year,
	CASE WHEN DATEDIFF(day, src.{{ sdts_alias }}, GETDATE()) between 366 and 730 THEN 1 ELSE 0 END as is_last_rolling_year,
	{# src.year, #}
	{# src.quarter, #}
	{# src.month, #}
	{# src.day_of_month, #}
	{# src.day_of_year, #}
	{# src.weekday, #}
	{# src.week, #}
	{# src.iso_week, #}
	src.is_hourly,
	src.is_daily,
	src.is_weekly,
	src.is_monthly,
	{# src.is_end_of_week, #}
	src.is_end_of_month,
	src.is_quarterly,
	{# src.is_end_of_quarter, #}
	src.is_yearly,
	src.is_end_of_year



FROM {{ ref(control_snap_v0) }} src
INNER JOIN in_the_past itp ON src.{{ sdts_alias }} = itp.{{ sdts_alias }}),

log_logic AS (

	SELECT

	*,

	{%- if log_logic is none %}
		1 AS {{ snapshot_trigger_column }},
	{% else %}
		{% for logic in ns.log_logic_list -%}

			{% for col_name, logic_definition in logic.items() -%}
				{{ log('logic_definition: ' ~ logic_definition, false) }}
				{{ log('col_name: ' ~ col_name, false) }}
				{%- set ns.col_name = col_name -%}
				{%- set ns.logic_definition = logic_definition %}
			{%- endfor -%}
			{%- set col_name = ns.col_name -%}
			{{ log('col_name: ' ~ col_name, false) }}
			{%- set logic_definition = ns.logic_definition -%}

			CASE 
				WHEN
				{% if 'daily' in logic_definition.keys() %}
					{%- if logic_definition['daily']['forever'] is true -%}
						{%- do ns.forever_status_dict.update({col_name: 'TRUE'}) -%}
					(1=1)
					{%- else %}                            
						{%- set daily_duration = logic_definition['daily']['duration'] -%}
						{%- set daily_unit = logic_definition['daily']['unit'] -%}
					(c.{{ sdts_alias }} BETWEEN DATEADD({{ daily_unit }}, -{{ daily_duration }}, GETDATE()) AND GETDATE())
					{%- endif -%}   
				{%- endif %}

				{%- if 'weekly' in logic_definition.keys() %} OR 
					{%- if logic_definition['weekly']['forever'] is true -%}
						{%- do ns.forever_status_dict.update({col_name: 'TRUE'}) -%}
				(DATEPART(weekday, c.{{ sdts_alias }}) = 7)
					{%- else %} 
						{%- set weekly_duration = logic_definition['weekly']['duration'] -%}
						{%- set weekly_unit = logic_definition['weekly']['unit'] %}            
				((c.{{ sdts_alias }} BETWEEN DATEADD({{ weekly_unit }}, -{{ weekly_duration }}, GETDATE()) AND GETDATE()) AND (DATEPART(weekday, c.{{ sdts_alias }}) = 7))
					{%- endif -%}
				{% endif -%}

				{%- if 'monthly' in logic_definition.keys() %} OR
					{%- if logic_definition['monthly']['forever'] is true -%}
						{%- do ns.forever_status_dict.update({col_name: 'TRUE'}) %}
				(c.is_end_of_month = 1)
					{%- else %}
						{%- set monthly_duration = logic_definition['monthly']['duration'] -%}
						{%- set monthly_unit = logic_definition['monthly']['unit'] %}            
				((c.{{ sdts_alias }} BETWEEN DATEADD({{ monthly_unit }}, -{{ monthly_duration }}, GETDATE()) AND GETDATE()) AND (c.is_end_of_month = 1))
					{%- endif -%}
				{% endif -%}

				{%- if 'yearly' in logic_definition.keys() %} OR 
					{%- if logic_definition['yearly']['forever'] is true -%}
						{%- do ns.forever_status_dict.update({col_name: 'TRUE'}) %}
				(c.is_end_of_year = 1)
					{%- else %}
						{%- set yearly_duration = logic_definition['yearly']['duration'] -%}
						{%- set yearly_unit = logic_definition['yearly']['unit'] %}                    
				((c.{{ sdts_alias }} BETWEEN DATEADD({{ yearly_unit }}, -{{ yearly_duration }}, GETDATE()) AND GETDATE()) AND (c.is_end_of_year = 1))
					{%- endif -%}
				{% endif %}
				THEN 1
				ELSE 0
			END AS {{ col_name }}{{ ',' if not loop.last }}
		{% endfor %}
	{%- endif %}

	FROM dynamic c

)

SELECT * FROM log_logic

{%- endmacro -%}

macro.datavault4dbt.fabric__eff_sat_v0.macro_sql:
{%- macro fabric__eff_sat_v0(source_model, tracked_hashkey, src_ldts, src_rsrc, is_active_alias, source_is_single_batch, disable_hwm, additional_columns) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ns = namespace(last_cte= "") -%}

{%- set source_relation = ref(source_model) -%}

{# Select the additional_columns and put them in an array. If additional_colums is none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set tracked_hashkey = datavault4dbt.escape_column_names(tracked_hashkey) -%}
{%- set is_active_alias = datavault4dbt.escape_column_names(is_active_alias) -%}
{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}

{%- set unknown_value_rsrc = var('datavault4dbt.default_unknown_rsrc', 'SYSTEM') -%}

{%- set is_active_datatype = var('datavault4dbt.is_active_datatype', 'Bit') -%}


WITH

{{ datavault4dbt.prepend_generated_by() }}

{#
    In all cases, the source model is selected, and optionally a HWM is applied. 
#}
{% if is_incremental() and not disable_hwm %}
max_ldts_prep AS (

    SELECT
        MAX({{ src_ldts }}) AS max_ldts
    FROM {{ this }}
    WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
),
{% endif %}

source_data AS (

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ src_ldts }},
        {{ src_rsrc }}
    FROM {{ source_relation }} src
    WHERE {{ src_ldts }} NOT IN ('{{ datavault4dbt.beginning_of_all_times() }}', '{{ datavault4dbt.end_of_all_times() }}')
    {%- if is_incremental() and not disable_hwm %}
    AND src.{{ src_ldts }} > (
        SELECT max_ldts FROM max_ldts_prep
    )
    {%- endif %}
),

{#
    In all incremental cases, the current status for each hashkey is selected from the existing Effectivity Satellite.
#}
{%- if is_incremental() %}
current_status_prep AS (

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ is_active_alias}},
        {{ src_rsrc }},
        ROW_NUMBER() OVER (PARTITION BY {{ tracked_hashkey }} ORDER BY {{ src_ldts }} DESC) as rn
    FROM {{ this }}

),

current_status AS (

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ is_active_alias }},
        {{ src_rsrc }}
    FROM current_status_prep
    WHERE rn = 1 

),
{% endif %}

{#
    This block is for multi-batch processing. 
#}
{% if not source_is_single_batch %}

    {#
        List of all Hashkeys with their date of first appearance in the source model.
    #}
    hashkeys AS (

        SELECT 
            {{ tracked_hashkey }},
            MIN({{ src_ldts }}) as first_appearance
        FROM source_data
        GROUP BY {{ tracked_hashkey }}

    ),

    {#
        Distinct list of load dates in the multi-batch source.
    #}
    load_dates AS (

        SELECT Distinct
            {{ src_ldts }}
        FROM source_data

    ),

    {#
        All combinations of hashkeys and loaddates, for loaddates after the first appearance of a hashkey.
    #}
    history AS (

        SELECT 
            hk.{{ tracked_hashkey }},
            ld.{{ src_ldts }}
        FROM hashkeys hk
        CROSS JOIN load_dates ld
        WHERE ld.{{ src_ldts }} >= hk.first_appearance

    ),

    {#
        All theoretical combinations are checked against the actual occurences of hashkeys in each batch / loaddate.
        If a Hashkey is part of a load/batch, is_active_alias is set to true, because the hashkey was active in that load/batch.
        If a Hashkey is not part of a load/batch, is_active_alias is set to false, because the hashkey was not active in that load/batch.
    #}
    is_active AS (

        SELECT
            h.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            src.{{ col }},
            {% endfor -%}
            h.{{ src_ldts }},
            COALESCE(src.{{ src_rsrc }}, '{{ unknown_value_rsrc }}') AS {{ src_rsrc }},
            CASE 
                WHEN src.{{ tracked_hashkey }} IS NULL THEN 0
                ELSE 1 
            END as {{ is_active_alias }}
        FROM history h
        LEFT JOIN source_data src
            ON src.{{ tracked_hashkey }} = h.{{ tracked_hashkey }}
            AND src.{{ src_ldts }} = h.{{ src_ldts }}

    ),

    {#
        The rows are deduplicated on the is_active_alias, to only include status changes.
    #}
    deduplicated_incoming_prep AS (

        SELECT
            is_active.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            is_active.{{ col }},
            {% endfor -%}
            is_active.{{ src_ldts }},
            is_active.{{ src_rsrc }},
            is_active.{{ is_active_alias }},
            LAG(is_active.{{ is_active_alias }}) OVER (PARTITION BY {{ tracked_hashkey }} ORDER BY {{ src_ldts }}) as lag_is_active

        FROM is_active

    ),

    deduplicated_incoming AS (

        SELECT
            deduplicated_incoming_prep.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            deduplicated_incoming_prep.{{ col }},
            {% endfor -%}
            deduplicated_incoming_prep.{{ src_ldts }},
            deduplicated_incoming_prep.{{ src_rsrc }},
            deduplicated_incoming_prep.{{ is_active_alias }}

        FROM
            deduplicated_incoming_prep
        WHERE
            deduplicated_incoming_prep.{{ is_active_alias }} != deduplicated_incoming_prep.lag_is_active
            OR deduplicated_incoming_prep.lag_is_active IS NULL

    ),

    {% set ns.last_cte = 'deduplicated_incoming' %}

{#
    This block is for single-batch processing
#}
{% else %}

    {#
        In initial loads of single-batch eff sats, every hashkey of the source is set to active.
    #}
    new_hashkeys AS (

        SELECT DISTINCT
            src.{{ tracked_hashkey }},
            {% for col in additional_columns -%}
            src.{{ col }},
            {% endfor -%}
            src.{{ src_ldts }},
            src.{{ src_rsrc }},
            1 as {{ is_active_alias }}
        FROM source_data src

        {#
            For incremental runs of single-batch eff sats, only hashkeys that are not active right now are set to active. 
            This automatically includes totally new hashkeys, or hashkeys that are currently set to inactive.
        #}
        {% if is_incremental() %}
            LEFT JOIN current_status cs
                ON src.{{ tracked_hashkey }} = cs.{{ tracked_hashkey }}
                AND cs.{{ is_active_alias }} = cast(1 as {{ is_active_datatype }})
            WHERE cs.{{ tracked_hashkey }} IS NULL
        {% endif %}

    ),

    {% set ns.last_cte = 'new_hashkeys' %}

{% endif %}

{#
    In all incremental runs, the source needs to be scanned for all currently active hashkeys. 
    If they are no longer present, they will be deactived. 
#}
{%- if is_incremental() %}

    {%- if not source_is_single_batch %}
        disappeared_hashkeys AS (

            SELECT DISTINCT 
                cs.{{ tracked_hashkey }},
                {% for col in additional_columns -%}
                null as {{ col }},
                {% endfor -%}
                ldts.min_ldts as {{ src_ldts }},
                '{{unknown_value_rsrc}}' AS {{ src_rsrc }},
                0 as {{ is_active_alias }}
            FROM current_status cs
            LEFT JOIN (
                SELECT 
                    MIN({{ src_ldts }}) as min_ldts
                FROM deduplicated_incoming) ldts
                ON 1 = 1
            LEFT JOIN deduplicated_incoming src
                ON src.{{ tracked_hashkey }} = cs.{{ tracked_hashkey }}
                AND  src.{{ src_ldts }} = ldts.min_ldts
            WHERE
                cs.{{ is_active_alias }} = 1
                AND src.{{ tracked_hashkey }} IS NULL
                AND ldts.min_ldts IS NOT NULL

        ),
    {% else %}
        disappeared_hashkeys AS (

            SELECT DISTINCT 
                cs.{{ tracked_hashkey }},
                {% for col in additional_columns -%}
                null as {{ col }},
                {% endfor -%}
                ldts.min_ldts as {{ src_ldts }},
                '{{unknown_value_rsrc}}' AS {{ src_rsrc }},
                0 as {{ is_active_alias }}
            FROM current_status cs
            LEFT JOIN (
                SELECT 
                    MIN({{ src_ldts }}) as min_ldts
                FROM source_data) ldts
                ON 1 = 1
            WHERE NOT EXISTS (
                SELECT 
                    1 
                FROM source_data src
                WHERE src.{{ tracked_hashkey }} = cs.{{ tracked_hashkey }}
            )
            AND cs.{{ is_active_alias }} = 1
            AND ldts.min_ldts IS NOT NULL

        ),
    {% endif %}
{%- endif %}

records_to_insert AS (

    {#
        This first part of the UNION includes:
            - for single-batch loads: Only is_active_alias = true, deactivations are handled later
            - for multi-batch loads: Ativation and deactivation inside the multiple loads
    #}
    SELECT
        di.{{ tracked_hashkey }},
        {% for col in additional_columns -%}
        di.{{ col }},
        {% endfor -%}
        di.{{ src_ldts }},
        di.{{ src_rsrc }},
        di.{{ is_active_alias }}
    FROM {{ ns.last_cte }} di


    {%- if is_incremental() %}

        {#
            For incremental multi-batch loads, the earliest to-be inserted status is compared to the current status. 
            It will only be inserted if the status changed.
        #} 
        {%- if not source_is_single_batch %}
            WHERE NOT EXISTS (
                SELECT 1
                FROM current_status
                WHERE {{ datavault4dbt.multikey(tracked_hashkey, prefix=['current_status', 'di'], condition='=') }}
                    AND cast(di.{{ is_active_alias }} as {{ is_active_datatype }}) = current_status.{{ is_active_alias }}
                    AND di.{{ src_ldts }} = (SELECT MIN({{ src_ldts }}) FROM deduplicated_incoming)
                )
            AND di.{{ src_ldts }} > (SELECT MAX({{ src_ldts }}) FROM {{ this }})
        {% endif %}

    {#
        For all incremental loads, the disappeared hashkeys are UNIONed.
    #}
    UNION

    SELECT
        {{ tracked_hashkey }},
        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}
        {{ src_ldts }},
        {{ src_rsrc }},
        {{ is_active_alias }}
    FROM disappeared_hashkeys

    {%- endif %}

)

SELECT 
    {{ tracked_hashkey }},
    {% for col in additional_columns -%}
    {{ col }},
