    {{ parent_hashkey }},
    {{ src_ldts }},
    {{ ns.hdiff_alias }},
    LAG({{ ns.hdiff_alias }}) OVER (PARTITION BY {{ parent_hashkey }} ORDER BY {{ src_ldts }}) as prev_ns_hdiff_alias
  FROM source_data
),

deduped_row_hashdiff AS (
  SELECT 
    {{ parent_hashkey }},
    {{ src_ldts }},
    {{ ns.hdiff_alias }}
  FROM lag_source_data
  WHERE {{ ns.hdiff_alias }} != prev_ns_hdiff_alias OR prev_ns_hdiff_alias IS NULL
),



{# Dedupe the source data regarding non-delta groups. #}
deduped_rows AS (

  SELECT 
    source_data.{{ parent_hashkey }},
    source_data.{{ ns.hdiff_alias }},
    {{ datavault4dbt.alias_all(columns=source_cols, prefix='source_data') }}
  FROM source_data
  INNER JOIN deduped_row_hashdiff
    ON {{ datavault4dbt.multikey(parent_hashkey, prefix=['source_data', 'deduped_row_hashdiff'], condition='=') }}
    AND {{ datavault4dbt.multikey(src_ldts, prefix=['source_data', 'deduped_row_hashdiff'], condition='=') }}
    AND {{ datavault4dbt.multikey(ns.hdiff_alias, prefix=['source_data', 'deduped_row_hashdiff'], condition='=') }}

),

records_to_insert AS (

    SELECT
        deduped_rows.{{ parent_hashkey }},
        deduped_rows.{{ ns.hdiff_alias }},
        {{ datavault4dbt.alias_all(columns=source_cols, prefix='deduped_rows') }}
    FROM deduped_rows
    {%- if is_incremental() %}
    WHERE NOT EXISTS (
        SELECT 1
        FROM latest_entries_in_sat
        WHERE {{ datavault4dbt.multikey(parent_hashkey, prefix=['latest_entries_in_sat', 'deduped_rows'], condition='=') }}
            AND {{ datavault4dbt.multikey(ns.hdiff_alias, prefix=['latest_entries_in_sat', 'deduped_rows'], condition='=') }} 
            )
    {%- endif %}

    )

SELECT * FROM records_to_insert

{%- endmacro -%}

macro.datavault4dbt.fabric__ma_sat_v1.macro_sql:
{%- macro fabric__ma_sat_v1(sat_v0, hashkey, hashdiff, ma_attribute, src_ldts, src_rsrc, ledts_alias, add_is_current_flag) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set is_current_col_alias = var('datavault4dbt.is_current_col_alias', 'IS_CURRENT') -%}
{%- set is_current_col_alias = datavault4dbt.escape_column_names(is_current_col_alias) -%}

{%- set source_relation = ref(sat_v0) -%}
{%- set all_columns = datavault4dbt.source_columns(source_relation=source_relation) -%}
{%- set exclude = datavault4dbt.expand_column_list(columns=[hashkey, hashdiff, ma_attribute, src_ldts, src_rsrc]) -%}

{%- set ma_attributes = datavault4dbt.expand_column_list(columns=[ma_attribute]) -%}
{% set ma_attributes = datavault4dbt.escape_column_names(ma_attributes) %}

{%- set source_columns_to_select = datavault4dbt.process_columns_to_select(all_columns, exclude) -%}
{% set source_columns_to_select = datavault4dbt.escape_column_names(source_columns_to_select) %}

{% set src_ldts = datavault4dbt.escape_column_names(src_ldts) %}
{% set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) %}
{% set ledts_alias = datavault4dbt.escape_column_names(ledts_alias) %}
{% set hashkey = datavault4dbt.escape_column_names(hashkey) %}
{% set hashdiff = datavault4dbt.escape_column_names(hashdiff) %}

WITH

{{ datavault4dbt.prepend_generated_by() }}

{# Getting everything from the underlying v0 satellite. #}
source_satellite AS (

    SELECT src.*
    FROM {{ source_relation }} as src

),

{# Selecting all distinct loads per hashkey. #}
distinct_hk_ldts AS (

    SELECT DISTINCT
        {{ hashkey }},
        {{ src_ldts }}
    FROM source_satellite

),

{# End-dating each ldts for each hashkey, based on earlier ldts per hashkey. #}
end_dated_loads AS (

  SELECT
    {{ hashkey }},
    {{ src_ldts }},
    COALESCE(
        DATEADD(MILLISECOND, -1, LEAD({{ src_ldts }}) OVER (PARTITION BY {{ hashkey }} ORDER BY {{ src_ldts }})),
        CAST('{{ end_of_all_times }}' AS DATETIME2(6))
    ) AS {{ ledts_alias }}
FROM distinct_hk_ldts

),

{# End-date each source record, based on the end-date for each load. #}
end_dated_source AS (

SELECT
    src.{{ hashkey }},
    src.{{ hashdiff }},
    src.{{ src_rsrc }},
    src.{{ src_ldts }},
    edl.{{ ledts_alias }},
    {%- if add_is_current_flag %}
        CASE WHEN edl.{{ ledts_alias }} = CAST('{{ end_of_all_times }}' AS DATETIME2(6))
        THEN 1
        ELSE 0
        END AS {{ is_current_col_alias }},
    {% endif %}
    {{- datavault4dbt.print_list(ma_attributes, indent=10, src_alias='src') }},
    {{- datavault4dbt.print_list(source_columns_to_select, indent=10, src_alias='src') }}
FROM source_satellite AS src
LEFT JOIN end_dated_loads edl
    ON src.{{ hashkey }} = edl.{{ hashkey }}
    AND src.{{ src_ldts }} = edl.{{ src_ldts }}


)

SELECT * FROM end_dated_source

{%- endmacro -%}

macro.datavault4dbt.fabric__nh_link.macro_sql:
{%- macro fabric__nh_link(link_hashkey, foreign_hashkeys, payload, source_models, src_ldts, src_rsrc, disable_hwm, source_is_single_batch, union_strategy, additional_columns) -%}

{%- set ns = namespace(last_cte= "", source_included_before = {}, has_rsrc_static_defined=true, source_models_rsrc_dict={}) -%}

{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{# Select the additional_columns from the nh-link model and put them in an array. If additional_colums none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{# If no specific link_hk, fk_columns, or payload are defined for each source, we apply the values set in the link_hashkey, foreign_hashkeys, and payload variable. #}
{# If no rsrc_static parameter is defined in ANY of the source models then the whole code block of record_source performance lookup is not executed  #}
{# For the use of record_source performance lookup it is required that every source model has the parameter rsrc_static defined and it cannot be an empty string #}
{%- if source_models is not mapping and not datavault4dbt.is_list(source_models) -%}
    {%- set source_models = {source_models: {}} -%}
{%- endif -%}

{%- set source_model_values = fromjson(datavault4dbt.source_model_processing(source_models=source_models, parameters={'link_hk':link_hashkey}, foreign_hashkeys=foreign_hashkeys, payload=payload)) -%}
{%- set source_models = source_model_values['source_model_list'] -%}
{#This loop goes through each source_model in the source_models list. For each model, it uses the ref() function to establish dependencies for dbt to track the relationships between models..#}
{%- for source_model in source_models -%}
    {%- set source_relation = ref(source_model.name) -%}
{%- endfor -%}

{%- if execute -%}

{%- set ns.has_rsrc_static_defined = source_model_values['has_rsrc_static_defined'] -%}
{%- set ns.source_models_rsrc_dict = source_model_values['source_models_rsrc_dict'] -%}
{{ log('source_models: '~source_models, false) }}

{% if union_strategy|lower == 'all' %}
    {% set union_command = 'UNION ALL' %}
{% elif union_strategy|lower == 'distinct' %}
    {% set union_command = 'UNION' %}
{% else %}
    {%- if execute -%}
        {%- do exceptions.warn("[" ~ this ~ "] Warning: Parameter 'union_strategy' set to '" ~ union_strategy ~ "' which is not a supported choice. Set to 'all' or 'distinct' instead. UNION ALL is used now.") -%}
    {% endif %}
    {% set union_command = 'UNION ALL' %}
{% endif %}

{%- if not datavault4dbt.is_something(foreign_hashkeys) -%}
    {%- set foreign_hashkeys = [] -%}
{%- endif -%}
{%- set final_columns_to_select = [link_hashkey] + foreign_hashkeys + [src_ldts] + [src_rsrc] + additional_columns + payload -%}

{%- set final_columns_to_select = datavault4dbt.escape_column_names(final_columns_to_select) -%}
{%- set link_hashkey = datavault4dbt.escape_column_names(link_hashkey) -%}
{%- set foreign_hashkeys = datavault4dbt.escape_column_names(foreign_hashkeys) -%}
{%- set payload = datavault4dbt.escape_column_names(payload) -%}
{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}

WITH

{{ datavault4dbt.prepend_generated_by() }}

{%- if is_incremental() -%}
    {%- if ns.has_rsrc_static_defined and not disable_hwm -%}
        {% for source_model in source_models %}
        {# Create a query with a rsrc_static column with each rsrc_static for each source model. #}
            {%- set source_number = source_model.id | string -%}
            {%- set rsrc_statics = ns.source_models_rsrc_dict[source_number] -%}

            {{log('rsrc_statics: '~ rsrc_statics, false) }}

            {%- set rsrc_static_query_source -%}
                SELECT count(*) FROM (
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT t.{{ (src_rsrc) }},
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }} t
                    WHERE {{ (src_rsrc) }} like '{{ (rsrc_static) }}'
                    {%- if not loop.last %}
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
                ) sub
            {% endset %}

            rsrc_static_{{ source_number }} AS (
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT t.*,
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }} t
                    WHERE {{ (src_rsrc) }} like '{{ (rsrc_static) }}'
                    {%- if not loop.last %}
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
                {%- set ns.last_cte = "rsrc_static_{}".format(source_number) -%}
            ),

            {%- set source_in_target = true -%}
            
            {%- if execute -%}
                {%- set rsrc_static_result = run_query(rsrc_static_query_source) -%}

                {%- set row_count = rsrc_static_result.columns[0].values()[0] -%}

                {{ log('row_count for '~source_model~' is '~row_count, false) }}

                {%- if row_count == 0 -%}
                    {%- set source_in_target = false -%}
                {%- endif -%}
            {%- endif -%}


            {%- do ns.source_included_before.update({source_model.id: source_in_target}) -%}

        {% endfor -%}

        {%- if source_models | length > 1 %}

        rsrc_static_union AS (
            {#  Create one unionized table over all sources. It will be the same as the already existing
                nh_link, but extended by the rsrc_static column. #}

            {% for source_model in source_models %}
            {%- set source_number = source_model.id | string -%}

            SELECT rsrc_static_{{ source_number }}.* FROM rsrc_static_{{ source_number }}

            {%- if not loop.last %}
            UNION ALL
            {% endif -%}
            {%- endfor %}
            {%- set ns.last_cte = "rsrc_static_union" -%}
        ),

        {%- endif %}

        max_ldts_per_rsrc_static_in_target AS (
        {# Use the previously created CTE to calculate the max load date timestamp per rsrc_static. #}

            SELECT
                rsrc_static,
                COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}) AS max_ldts
            FROM {{ ns.last_cte }}
            WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
            GROUP BY rsrc_static

        ),
    {%- endif %}
{% endif -%}

{% for source_model in source_models %}

{#  Select all deduplicated records from each source, and filter for records that are newer
    than the max ldts inside the existing link, if incremental. #}

    {%- set source_number = source_model.id | string -%}

    {%- if ns.has_rsrc_static_defined -%}
        {%- set rsrc_statics = ns.source_models_rsrc_dict[source_number|string] -%}
    {%- endif -%}

    {%- if 'link_hk' not in source_model.keys() %}
        {%- set link_hk = link_hashkey -%}
    {%- else -%}
        {%- set link_hk = source_model['link_hk'] -%}
    {% endif %}

src_new_{{ source_number }} AS (

    SELECT
            {{ datavault4dbt.escape_column_names(link_hk) }} AS {{ link_hashkey }},
            {% for fk in source_model['fk_columns'] -%}
            {{ datavault4dbt.escape_column_names(fk) }},
            {% endfor -%}

        {% for col in additional_columns -%}
            {{ col }},
        {% endfor -%}

        {{ src_ldts }},
        {{ src_rsrc }},

        {{ datavault4dbt.print_list(datavault4dbt.escape_column_names(source_model['payload'])) | indent(3) }}

    FROM {{ ref(source_model.name) }} src
    {# If the model is incremental and all sources has rsrc_static defined and valid and the source was already included before in the target transactional link #}
    {# then an inner join is performed on the CTE for the maximum load date timestamp per record source static to get the records
    that match any of the rsrc_static present in it #}
    {# if there are records in the source with a newer load date time stamp than the ones present in the target, those will be selected to be inserted later #}
    {%- if is_incremental() and ns.has_rsrc_static_defined and ns.source_included_before[source_number|int] and not disable_hwm %}
        INNER JOIN max_ldts_per_rsrc_static_in_target max ON
        ({%- for rsrc_static in rsrc_statics -%}
            max.rsrc_static = '{{ rsrc_static }}'
            {%- if not loop.last -%} OR
            {% endif -%}
        {%- endfor %})
        WHERE src.{{ src_ldts }} > max.max_ldts
    {%- elif is_incremental() and source_models | length == 1 and not ns.has_rsrc_static_defined and not disable_hwm %}
        WHERE src.{{ src_ldts }} > (
            SELECT COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }})
            FROM {{ this }}
            WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
            )
    {%- endif %}

    {%- set ns.last_cte = "src_new_{}".format(source_number) %}

    ),
{%- endfor -%}

{%- if source_models | length > 1 %}

source_new_union AS (
{# Unionize the new records from all sources. #}

    {%- for source_model in source_models -%}

    {%- set source_number = source_model.id | string -%}

    SELECT
        {{ link_hashkey }},
        {% for fk in source_model['fk_columns']|list %}
            {{ datavault4dbt.escape_column_names(fk) }} AS {{ datavault4dbt.escape_column_names(foreign_hashkeys[loop.index - 1]) }},
        {% endfor -%}

        {% for col in additional_columns -%}
            {{ col }},
        {% endfor -%}

        {{ src_ldts }},
        {{ src_rsrc }},

        {% for col in source_model['payload']|list %}
            {{ (col) }} AS {{ (payload[loop.index - 1]) }}
            {%- if not loop.last %}, {%- endif %}
        {% endfor -%}

    FROM src_new_{{ source_number }}

    {%- if not loop.last %}
    {{ union_command }}
    {% endif -%}

    {%- endfor -%}

    {%- set ns.last_cte = 'source_new_union' -%}

),

{%- endif %}

{%- if not source_is_single_batch %}

earliest_hk_over_all_sources_prep AS (
{# Deduplicate the unionized records again to only insert the earliest one. #}

    SELECT
        lcte.*,
        ROW_NUMBER() OVER (PARTITION BY {{ link_hashkey }} ORDER BY {{ src_ldts }}) AS rn
    FROM {{ ns.last_cte }} AS lcte


),

earliest_hk_over_all_sources AS (

    SELECT 
        {{ datavault4dbt.print_list((final_columns_to_select)) | indent(4) }}
    FROM earliest_hk_over_all_sources_prep
    WHERE rn = 1

    {%- set ns.last_cte = 'earliest_hk_over_all_sources' -%}
),

{%- endif %}

{%- if is_incremental() %}
{# Get all link hashkeys out of the existing link for later incremental logic. #}
    distinct_target_hashkeys AS (
        
        SELECT
        {{ link_hashkey }}
        FROM {{ this }}
        WHERE 1=1

        {{ datavault4dbt.filter_distinct_target_hashkey_in_nh_link() }}

    ),
{% endif %}

records_to_insert AS (
{# Select everything from the previous CTE, if its incremental then filter for hashkeys that are not already in the link. #}

    SELECT
        {{ datavault4dbt.print_list((final_columns_to_select)) | indent(4) }}
    FROM {{ ns.last_cte }} cte

    {%- if is_incremental() %}
    WHERE
        NOT EXISTS (
            SELECT 1
            FROM distinct_target_hashkeys dth
            WHERE cte.{{ link_hashkey }} = dth.{{ link_hashkey }}
        )
    {% endif %}
)

SELECT * FROM records_to_insert
{% endif %}

{%- endmacro -%}

macro.datavault4dbt.fabric__nh_sat.macro_sql:
{%- macro fabric__nh_sat(parent_hashkey, src_payload, src_ldts, src_rsrc, source_model, source_is_single_batch, additional_columns) -%}

{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{# Select the additional_columns and put them in an array. If additional_colums is none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set source_cols = datavault4dbt.expand_column_list(columns=[parent_hashkey, src_ldts, src_rsrc, src_payload, additional_columns]) -%}

{%- set source_relation = ref(source_model) -%}

{%- set ns = namespace(last_cte='') -%}


{%- set source_cols = datavault4dbt.escape_column_names(source_cols) -%}
{%- set parent_hashkey = datavault4dbt.escape_column_names(parent_hashkey) -%}
{%- set src_payload = datavault4dbt.escape_column_names(src_payload) -%}
{%- set src_ldts = datavault4dbt.escape_column_names(src_ldts) -%}
{%- set src_rsrc = datavault4dbt.escape_column_names(src_rsrc) -%}

WITH

{{ datavault4dbt.prepend_generated_by() }}

{# Selecting all source data, that is newer than latest data in sat if incremental #}
source_data AS (

    SELECT
        
        {{ datavault4dbt.print_list(source_cols) }}
        
    {% if not source_is_single_batch -%}
        , ROW_NUMBER() OVER (PARTITION BY {{ parent_hashkey }} ORDER BY {{ src_ldts }}) as RN
    {%- endif %}

    FROM 
        {{ source_relation }}
    {%- if is_incremental() %}
    WHERE {{ src_ldts }} > (
        SELECT
            COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }})
        FROM 
            {{ this }}
        WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    )
    {%- endif %}

    {%- set ns.last_cte = 'source_data' -%}
),

{% if not source_is_single_batch -%}

deduped_source AS (

    SELECT 
        {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ ns.last_cte }}
    WHERE RN = 1

    {%- set ns.last_cte = 'deduped_source' -%}

),

{%- endif %} 

{% if is_incremental() -%}
{#- Get distinct list of hashkeys inside the existing satellite, if incremental. #}
distinct_hashkeys AS 
(
    SELECT DISTINCT
        {{ parent_hashkey }}
    FROM 
        {{ this }}    
    WHERE 1=1

    {{ datavault4dbt.filter_distinct_target_hashkey_in_nh_sat() }}
    
    ),
{%- endif %}

{#- 
    Select all records from the source. If incremental, insert only records, where the
    hashkey is not already in the existing satellite.
#}
records_to_insert AS (

    SELECT
        {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ ns.last_cte }} cte
    {%- if is_incremental() %}
    WHERE 
        NOT EXISTS (
            SELECT 1
            FROM distinct_hashkeys dth
            WHERE cte.{{ parent_hashkey }} = dth.{{ parent_hashkey }}
        )
    {%- endif %}
    )
SELECT 
  * 
FROM 
  records_to_insert

{%- endmacro -%}

macro.datavault4dbt.fabric__pit.macro_sql:
{%- macro fabric__pit(tracked_entity, hashkey, sat_names, ldts, ledts, sdts, snapshot_relation, dimension_key, refer_to_ghost_records, snapshot_trigger_column=none, custom_rsrc=none, pit_type=none, snapshot_optimization=false) -%}

{%- set hash = var('datavault4dbt.hash', 'MD5') -%}
{%- set hash_dtype = var('datavault4dbt.hash_datatype', 'VARBINARY(16)') -%}
{%- set hash_default_values = fromjson(datavault4dbt.hash_default_values(hash_function=hash,hash_datatype=hash_dtype)) -%}
{%- set hash_alg = hash_default_values['hash_alg'] -%}
{%- set unknown_key = hash_default_values['unknown_key'] -%}
{%- set error_key = hash_default_values['error_key'] -%}

{%- set rsrc = var('datavault4dbt.rsrc_alias', 'rsrc') -%}
{%- set rsrc = datavault4dbt.escape_column_names(rsrc) -%}

{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- if datavault4dbt.is_something(pit_type) -%}
    {%- set quote = "'" -%}
    {%- set pit_type_quoted = quote + pit_type + quote -%}
    {%- set hashed_cols = [pit_type_quoted, datavault4dbt.prefix([hashkey],'te'), datavault4dbt.prefix([sdts], 'snap')] -%}
{%- else -%}
    {%- set hashed_cols = [datavault4dbt.prefix([hashkey],'te'), datavault4dbt.prefix([sdts], 'snap')] -%}
{%- endif -%}

{%- set hashkey = datavault4dbt.escape_column_names(hashkey) -%}
{%- set sdts = datavault4dbt.escape_column_names(sdts) -%}
{%- set ldts = datavault4dbt.escape_column_names(ldts) -%}
{%- set ledts = datavault4dbt.escape_column_names(ledts) -%}

WITH

{{ datavault4dbt.prepend_generated_by() }}

{%- if is_incremental() %}

existing_dimension_keys AS (

    SELECT
        {{ dimension_key }}
    FROM {{ this }}

),

{%- endif %}

pit_records AS (

    SELECT
        
        {% if datavault4dbt.is_something(pit_type) -%}
            {{ datavault4dbt.as_constant(pit_type) }} as {{ datavault4dbt.escape_column_names('type') }},
        {%- endif %}
        {% if datavault4dbt.is_something(custom_rsrc) -%}
        '{{ custom_rsrc }}' as {{ rsrc }},
        {%- endif %}
        {{ datavault4dbt.hash(columns=hashed_cols,
                    alias=datavault4dbt.escape_column_names(dimension_key),
                    is_hashdiff=false)   }} ,
        te.{{ hashkey }},
        snap.{{ sdts }},
        {%- for satellite in sat_names %}
          {% if refer_to_ghost_records %}
            COALESCE({{ satellite }}.{{ hashkey }}, CAST({{ datavault4dbt.as_constant(column_str=unknown_key) }} as {{ hash_dtype }})) AS {{datavault4dbt.escape_column_names('hk_'~ satellite)}},
            COALESCE({{ satellite }}.{{ ldts }}, {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}) AS {{ datavault4dbt.escape_column_names(ldts~'_'~satellite)}}
          {% else %}
            {{ satellite }}.{{ hashkey }} AS {{datavault4dbt.escape_column_names('hk_'~ satellite)}},
            {{ satellite }}.{{ ldts }} AS {{ datavault4dbt.escape_column_names(ldts~'_'~satellite)}}
          {% endif %}
          {{- "," if not loop.last }}
        {%- endfor %}

    FROM
            {{ ref(tracked_entity) }} te
        INNER JOIN
            {{ ref(snapshot_relation) }} snap
            {% if datavault4dbt.is_something(snapshot_trigger_column) -%}
                ON snap.{{ snapshot_trigger_column }} = 1
