         {%- set ns.last_cte = "src_new_{}".format(source_number) %}
         
    ),
{%- endfor -%}

{%- if source_models | length > 1 %}

source_new_union AS (

    {%- for source_model in source_models -%}

    {%- set source_number = source_model.id | string -%}

