            {{ datavault4dbt.escape_column_names(ref_key) }} AS {{ datavault4dbt.escape_column_names(ref_keys[loop.index - 1]) }},
        {% endfor -%}

        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}

