        FROM {{ this }}
    )
{%- endif -%}


),

ref_table AS (

    SELECT
    {{ datavault4dbt.print_list(list_to_print=datavault4dbt.escape_column_names(ref_key_cols), indent=2, src_alias='h') }},
        ld.{{ datavault4dbt.escape_column_names(date_column) }},
