macro.datavault4dbt.oracle__ref_sat_v0.macro_sql:
{%- macro oracle__ref_sat_v0(parent_ref_keys, src_hashdiff, src_payload, src_ldts, src_rsrc, source_model, disable_hwm, source_is_single_batch, additional_columns) -%}

