{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set ns = namespace(last_cte = '', source_included_before = {},  source_models_rsrc_dict={},  has_rsrc_static_defined=true) -%}

{%- if source_models is not mapping and not datavault4dbt.is_list(source_models) -%}
    {%- set source_models = {source_models: {}} -%}
{%- endif -%}

{%- set source_model_values = fromjson(datavault4dbt.source_model_processing(source_models=source_models, parameters={'hk_column':tracked_hashkey})) -%}
{%- set source_models = source_model_values['source_model_list'] -%}
{%- set ns.has_rsrc_static_defined = source_model_values['has_rsrc_static_defined'] -%}
{%- set ns.source_models_rsrc_dict = source_model_values['source_models_rsrc_dict'] -%}
{{ log('source_models: '~source_models, false) }}

{%- set final_columns_to_select = [tracked_hashkey] + [src_ldts] + [src_rsrc] + [src_stg] + additional_columns -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{% if is_incremental() %}

    distinct_target AS ( 
        {{ "\n" }}
        SELECT
             {{ tracked_hashkey }}
            ,{{ src_ldts }}
            ,{{ src_rsrc }}
        FROM {{ this }}
    ),
    {%- if ns.has_rsrc_static_defined and not disable_hwm -%}
        rsrc_static_unionized AS (
        {% for source_model in source_models %}
        {# Create a query with a rsrc_static column with each rsrc_static for each source model. #}
              {%- set source_number = source_model.id | string -%}
            {%- set hk_column = source_model['hk_column'] -%}
            {%- set rsrc_statics = ns.source_models_rsrc_dict[source_number] -%}

            {%- set rsrc_static_query_source_count -%}
                SELECT count(*) FROM (
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT 
                    {{ tracked_hashkey }},
                    {{ src_ldts }},
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }}
                    WHERE {{ src_rsrc }} like '{{ rsrc_static }}'
                    {%- if not loop.last %} 
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
                ) sub
            {% endset %}

            {%- set rsrc_static_query_source -%}
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT 
                    {{ tracked_hashkey }},
                    {{ src_ldts }},
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }}
                    WHERE {{ src_rsrc }} like '{{ rsrc_static }}'
                    {%- if not loop.last %} 
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
            {% endset %}

            {{ rsrc_static_query_source }}  

            {%- set source_in_target = true -%}
            
            {%- if execute -%}
                {%- set rsrc_static_result = run_query(rsrc_static_query_source_count) -%}

                {%- set row_count = rsrc_static_result.columns[0].values()[0] -%}

                {{ log('row_count for '~source_model~' is '~row_count, false) }}

                {%- if row_count == 0 -%}
                    {%- set source_in_target = false -%}
                {%- endif -%}
            {%- endif -%}

            {%- do ns.source_included_before.update({source_model.id: source_in_target}) -%}
            {# Unionize over all sources #}
            {%- if not loop.last %}
                UNION ALL 
            {% endif -%}

        {% endfor -%}
        {%- set ns.last_cte = "rsrc_static_unionized" -%}
        ),

        max_ldts_per_rsrc_static_in_target AS (

            SELECT
                rsrc_static,
                COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}) as max_ldts
            FROM {{ ns.last_cte }}
            WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
            GROUP BY rsrc_static

        ),
    {%- endif %}
{% endif -%}

{#
    We deduplicate each source over hashkey + ldts + rsrc_static and if is_incremental only select the rows, where the ldts is later
    than the latest one in the existing satellite for that rsrc_static. If a source is added to the existing satellite, all deduplicated
    rows from that source are loaded into the satellite.
#}

{%- for source_model in source_models %}

    {%- set source_number = source_model.id | string -%}
    {%- set hk_column = source_model['hk_column'] -%}
    {%- if ns.has_rsrc_static_defined -%}
        {%- set rsrc_statics = ns.source_models_rsrc_dict[source_number|string] -%}

        src_new_{{ source_number }} AS (
        {%- for rsrc_static in rsrc_statics %}
            SELECT DISTINCT
                {{ hk_column }} AS {{ tracked_hashkey }},
                {{ src_ldts }},
                CAST('{{ rsrc_static }}' AS {{ rsrc_default_dtype }} ) AS {{ src_rsrc }},
                CAST(UPPER('{{ source_model.name }}') AS {{ stg_default_dtype }})  AS {{ src_stg }}
                {% for col in additional_columns -%}
                ,{{ col }}
                {% endfor -%}
            FROM {{ ref(source_model.name) }} src


            {%- if is_incremental() and ns.has_rsrc_static_defined and ns.source_included_before[source_number|int] and not disable_hwm %}
                INNER JOIN max_ldts_per_rsrc_static_in_target max
                    ON max.rsrc_static = '{{ rsrc_static }}'
                WHERE src.{{ src_ldts }} > max.max_ldts
            {%- endif %}
            {%- if not loop.last %}
                UNION ALL
            {% endif -%}
        {% endfor %}

        ),
    {%- else -%}
        src_new_{{ source_number}} AS (
            SELECT DISTINCT
                {{ hk_column }} AS {{ tracked_hashkey }},
                {{ src_ldts }},
                CAST({{ src_rsrc }} AS {{ rsrc_default_dtype }}) AS {{ src_rsrc }},
                CAST(UPPER('{{ source_model.name }}') AS {{ stg_default_dtype }}) AS {{ src_stg }}
                {% for col in additional_columns -%}
                ,{{ col }}
                {% endfor -%}
            FROM {{ ref(source_model.name) }} src
            {%- if is_incremental() and source_models | length == 1 and not disable_hwm %}
                WHERE src.{{ src_ldts }} > (
            SELECT COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }})
            FROM {{ this }}
            WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
            )
            {%- endif %}
        ),
    {%- endif -%}

    {%- set ns.last_cte = "src_new_{}".format(source_number) %}

{% endfor %}

{#
    If more than one source model is selected, all previously created deduplicated CTEs are unionized.
#}

{%- if source_models | length > 1 %}

source_new_union AS (
    {% for source_model in source_models %}
        {%- set hk_column = source_model['hk_column'] -%}
        {%- set source_number = source_model.id | string -%}

        SELECT
        {{ tracked_hashkey }},
        {{ src_ldts }},
        {{ src_rsrc }},
        {{ src_stg }}
        {% for col in additional_columns -%}
        ,{{ col }}
        {% endfor -%}
        FROM src_new_{{ source_number }}

        {%- if not loop.last %}
        UNION ALL
        {% endif -%}

    {% endfor %}

    {%- set ns.last_cte = 'source_new_union' -%}

),

{%- endif -%}

{#
    Selecting everything, either from the unionized data, or from the single CTE (if single source). Checking against the existing
    satellite to only inserts that are not already inserted, if incremental run.
#}

records_to_insert AS (

    SELECT
    {{ datavault4dbt.print_list(final_columns_to_select) }}
    FROM {{ ns.last_cte }} cte
    WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }} 
    AND {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}
    {%- if is_incremental() %}
        AND 
            NOT EXISTS (
                SELECT 1
                FROM distinct_target dt
                WHERE 1=1
                    AND dt.{{ tracked_hashkey }} = cte.{{ tracked_hashkey }}
                    AND dt.{{ src_ldts }} = cte.{{ src_ldts }}
                    AND dt.{{ src_rsrc }} = cte.{{ src_rsrc }}
            )
    {% endif %}
)

SELECT * FROM records_to_insert

{%- endmacro -%}

macro.datavault4dbt.synapse__ref_hub.macro_sql:
{%- macro synapse__ref_hub(ref_keys, src_ldts, src_rsrc, source_models, additional_columns) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ns = namespace(last_cte= "", source_included_before = {}, has_rsrc_static_defined=true, source_models_rsrc_dict={}) -%}

{%- set ref_keys = datavault4dbt.expand_column_list(columns=[ref_keys]) -%}

{# Select the additional_columns and put them in an array. If additional_colums none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{# If no specific ref_keys is defined for each source, we apply the values set in the ref_keys variable. #}
{# If no rsrc_static parameter is defined in ANY of the source models then the whole code block of record_source performance lookup is not executed  #}
{# For the use of record_source performance lookup it is required that every source model has the parameter rsrc_static defined and it cannot be an empty string #}
{%- if source_models is not mapping and not datavault4dbt.is_list(source_models) -%}
    {%- set source_models = {source_models: {}} -%}
{%- endif -%}

{%- set source_model_values = fromjson(datavault4dbt.source_model_processing(source_models=source_models, parameters={'test':'test'}, reference_keys=ref_keys)) -%}
{%- set source_models = source_model_values['source_model_list'] -%}
{%- set ns.has_rsrc_static_defined = source_model_values['has_rsrc_static_defined'] -%}
{%- set ns.source_models_rsrc_dict = source_model_values['source_models_rsrc_dict'] -%}
{{ log('source_models: '~source_models, false) }}

{%- set final_columns_to_select = ref_keys + [src_ldts] + [src_rsrc] + additional_columns -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{% if is_incremental() -%}
{# Get all target ref_keys out of the existing ref_table for later incremental logic. #}
    distinct_target_ref_keys AS (

        SELECT
            {% for ref_key in ref_keys -%}
            {{ ref_key}} {%- if not loop.last %},{% endif %}
            {% endfor %}
        FROM {{ this }}

    ),
    {%- if ns.has_rsrc_static_defined -%}
        {% for source_model in source_models %}
         {# Create a query with a rsrc_static column with each rsrc_static for each source model. #}
            {%- set source_number = source_model.id | string -%}
            {%- set rsrc_statics = ns.source_models_rsrc_dict[source_number] -%}

            {{log('rsrc_statics: '~ rsrc_statics, false) }}

            {%- set rsrc_static_query_source -%}
                SELECT count(*) FROM (
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT t.{{ src_rsrc }},
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }} t
                    WHERE {{ src_rsrc }} like '{{ rsrc_static }}'
                    {%- if not loop.last %}
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
                ) sub
            {% endset %}

            rsrc_static_{{ source_number }} AS (
                {%- for rsrc_static in rsrc_statics -%}
                    SELECT 
                    t.{{ src_ldts }},
                    '{{ rsrc_static }}' AS rsrc_static
                    FROM {{ this }} t
                    WHERE {{ src_rsrc }} LIKE '{{ rsrc_static }}'
                    {%- if not loop.last %}
                        UNION ALL
                    {% endif -%}
                {%- endfor -%}
                {%- set ns.last_cte = "rsrc_static_{}".format(source_number) -%}
            ),

            {%- set source_in_target = true -%}

            {%- if execute -%}
                {%- set rsrc_static_result = run_query(rsrc_static_query_source) -%}

                {%- set row_count = rsrc_static_result.columns[0].values()[0] -%}

                {{ log('row_count for '~source_model~' is '~row_count, false) }}

                {%- if row_count == 0 -%}
                {%- set source_in_target = false -%}
                {%- endif -%}
            {%- endif -%}


            {%- do ns.source_included_before.update({source_model.id: source_in_target}) -%}

        {% endfor -%}

        {%- if source_models | length > 1 %}

        rsrc_static_union AS (
            {#  Create one unionized table over all sources. It will be the same as the already existing
                hub, but extended by the rsrc_static column. #}
            {% for source_model in source_models %}
            {%- set source_number = source_model.id | string -%}

            SELECT rsrc_static_{{ source_number }}.* FROM rsrc_static_{{ source_number }}

            {%- if not loop.last %}
            UNION ALL
            {% endif -%}
            {%- endfor %}
            {%- set ns.last_cte = "rsrc_static_union" -%}
        ),

        {%- endif %}

        max_ldts_per_rsrc_static_in_target AS (
        {# Use the previously created CTE to calculate the max load date timestamp per rsrc_static. #}
            SELECT
                rsrc_static,
                COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}) as max_ldts
            FROM {{ ns.last_cte }}
            WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
            GROUP BY rsrc_static

        ),
    {%- endif %}
{% endif -%}

{% for source_model in source_models %}

    {%- set source_number = source_model.id | string -%}

    {%- if ns.has_rsrc_static_defined -%}
        {%- set rsrc_statics = ns.source_models_rsrc_dict.id -%}
    {%- endif -%}


    src_new_{{ source_number }} AS (

        SELECT
            {% for ref_key in source_model['ref_keys'] -%}
            {{ ref_key}},
            {% endfor -%}

            {% for col in additional_columns -%}
            {{ col }},
            {% endfor -%}

            {{ src_ldts }},
            {{ src_rsrc }}
        FROM {{ ref(source_model.name) }} src
        WHERE NOT (
            {% for ref_key in source_model['ref_keys'] -%}
            {{ ref_key}} IS NULL {%- if not loop.last %} AND {% endif -%}
            {% endfor -%} )

    {%- if is_incremental() and ns.has_rsrc_static_defined and ns.source_included_before[source_number|int] and not disable_hwm %}
        INNER JOIN max_ldts_per_rsrc_static_in_target max ON
        ({%- for rsrc_static in rsrc_statics -%}
            max.rsrc_static = '{{ rsrc_static }}'
            {%- if not loop.last -%} OR
            {% endif -%}
        {%- endfor %})
        AND src.{{ src_ldts }} > max.max_ldts
    {%- elif is_incremental() and source_models | length == 1 and not ns.has_rsrc_static_defined and not disable_hwm %}
        AND src.{{ src_ldts }} > (
            SELECT COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }})
            FROM {{ this }}
            WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
            )
    {%- endif %}

         {%- set ns.last_cte = "src_new_{}".format(source_number) %}
         
    ),
{%- endfor -%}

{%- if source_models | length > 1 %}

source_new_union AS (

    {%- for source_model in source_models -%}

    {%- set source_number = source_model.id | string -%}

    SELECT
        {% for ref_key in source_model['ref_keys'] -%}
            {{ ref_key }} AS {{ ref_keys[loop.index - 1] }},
        {% endfor -%}

        {% for col in additional_columns -%}
        {{ col }},
        {% endfor -%}

        {{ src_ldts }},
        {{ src_rsrc }}
    FROM src_new_{{ source_number }}

    {%- if not loop.last %}
    UNION ALL
    {% endif -%}

    {%- endfor -%}

    {%- set ns.last_cte = 'source_new_union' -%}

),

{%- endif %}

prep_earliest_ref_key_over_all_sources AS (

    {#- Prepare unionized records to only insert the earliest one. #}
    SELECT
        lcte.*
        , ROW_NUMBER() OVER (PARTITION BY {%- for ref_key in ref_keys %} {{ref_key}} {%- if not loop.last %}, {% endif %}{% endfor %} ORDER BY {{ src_ldts }}) AS SEQ
    FROM {{ ns.last_cte }} AS lcte

    {%- set ns.last_cte = 'prep_earliest_ref_key_over_all_sources' -%}

),
earliest_ref_key_over_all_sources AS (

    {#- Deduplicate the unionized records to only insert the earliest one. #}
    SELECT
        lcte.*
    FROM {{ ns.last_cte }} AS lcte
    WHERE SEQ = 1

    {%- set ns.last_cte = 'earliest_ref_key_over_all_sources' -%}

),
records_to_insert AS (
    {#- Select everything from the previous CTE, if incremental filter for hashkeys that are not already in the hub. #}
    SELECT
        {{ datavault4dbt.print_list(final_columns_to_select) }}
    FROM {{ ns.last_cte }} cte

    {%- if is_incremental() %}
    WHERE NOT EXISTS (
        SELECT 
            1 
        FROM distinct_target_ref_keys dtr
        WHERE 
            {% for ref_key in ref_keys -%}
            {% if not loop.first %}AND {% endif -%} cte.{{ ref_key}} = dtr.{{ ref_key }}
            {% endfor -%}
         )
        {% for ref_key in ref_keys -%}
            AND cte.{{ ref_key}} IS NOT NULL
        {% endfor -%}
    {% endif -%}
)

SELECT * FROM records_to_insert

{%- endmacro -%}

macro.datavault4dbt.synapse__ref_sat_v0.macro_sql:
{%- macro synapse__ref_sat_v0(parent_ref_keys, src_hashdiff, src_payload, src_ldts, src_rsrc, source_model, disable_hwm, source_is_single_batch, additional_columns) -%}

{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set parent_ref_keys = datavault4dbt.expand_column_list(columns=[parent_ref_keys]) -%}

{%- set ns=namespace(src_hashdiff="", hdiff_alias="") %}

{%- if  src_hashdiff is mapping and src_hashdiff is not none -%}
    {% set ns.src_hashdiff = src_hashdiff["source_column"] %}
    {% set ns.hdiff_alias = src_hashdiff["alias"] %}
{% else %}
    {% set ns.src_hashdiff = src_hashdiff %}
    {% set ns.hdiff_alias = src_hashdiff  %}
{%- endif -%}

{# Select the additional_columns and put them in an array. If additional_colums none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set source_cols = datavault4dbt.expand_column_list(columns=[src_rsrc, src_ldts, src_payload, additional_columns]) -%}

{%- set source_relation = ref(source_model) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Selecting all source data, that is newer than latest data in ref_sat if incremental #}
source_data AS (

    SELECT
        {% for ref_key in parent_ref_keys %}
        {{ref_key}},
        {%- endfor %}
        {{ ns.src_hashdiff }} as {{ ns.hdiff_alias }},
        {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ source_relation }}

    {%- if is_incremental()  and not disable_hwm %}
    WHERE {{ src_ldts }} > (
        SELECT
            COALESCE (MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}) FROM {{ this }}
        WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    )
    AND {{ src_ldts }} <> {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    {%- endif %}
    
    {%- set source_cte = 'source_data' -%}

    -- UNION ALL ghost record 000000
),

{# Adding window functions row_number and lag to target #}
{%- if is_incremental() %}
target_data AS (

    SELECT
        {% for ref_key in parent_ref_keys %}
        {{ref_key}},
        {% endfor %}
        {{ ns.hdiff_alias }}
        , ROW_NUMBER() OVER(PARTITION BY {%- for ref_key in parent_ref_keys %} {{ref_key}} {%- if not loop.last %}, {% endif %}{% endfor %} ORDER BY {{ src_ldts }} DESC) AS rn
    FROM 
        {{ this }}
),
{%- endif %}

{# Get the latest record for each parent ref key combination in existing sat, if incremental. #}
{%- if is_incremental() %}
latest_entries_in_sat AS (

    SELECT
        {% for ref_key in parent_ref_keys %}
        {{ref_key}},
        {% endfor %}
        {{ ns.hdiff_alias }}
    FROM 
        target_data
    WHERE rn = 1
),
{%- endif %}

{%- if not source_is_single_batch %}

{#
    Adding hashdiff of the previous record, for each parent ref key combination.
#}
numbered_source AS (

    SELECT
    {% for ref_key in parent_ref_keys %}
    {{ref_key}},
    {% endfor %}
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    , LAG({{ ns.hdiff_alias }}) OVER(PARTITION BY {%- for ref_key in parent_ref_keys %} {{ref_key}} {%- if not loop.last %}, {% endif %}{% endfor %} ORDER BY {{ src_ldts }}) prev_hashdiff
    FROM source_data
),

{#
    Deduplicate source by comparing each hashdiff to the hashdiff of the previous record, for each parent ref key combination.
    Additionally adding a row number based on that order, if incremental.
#}
deduplicated_numbered_source AS (

    SELECT
    {% for ref_key in parent_ref_keys %}
    {{ref_key}},
    {% endfor %}
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    {% if is_incremental() -%}
    , ROW_NUMBER() OVER(PARTITION BY {%- for ref_key in parent_ref_keys %} {{ref_key}} {%- if not loop.last %}, {% endif %}{% endfor %} ORDER BY {{ src_ldts }}) as rn
    {%- endif %}
    FROM numbered_source
    WHERE {{ ns.hdiff_alias }} <> prev_hashdiff OR prev_hashdiff IS NULL

    {%- set source_cte = 'deduplicated_numbered_source' -%}

),

{% endif -%}

{#
    Select all records from the previous CTE. If incremental, compare the oldest incoming entry to
    the existing records in the satellite.
#}
records_to_insert AS (

    SELECT
    {% for ref_key in parent_ref_keys %}
    {{ref_key}},
    {% endfor %}
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ source_cte }} sc
    {%- if is_incremental() %}
    WHERE NOT EXISTS (
        SELECT 1
        FROM latest_entries_in_sat
        WHERE 1=1
            {% for ref_key in parent_ref_keys %}
            AND {{ datavault4dbt.multikey(ref_key, prefix=['latest_entries_in_sat', 'sc'], condition='=') }}
            {% endfor %}
            AND {{ datavault4dbt.multikey(ns.hdiff_alias, prefix=['latest_entries_in_sat', 'sc'], condition='=') }}
            {%- if not source_is_single_batch %}
            AND sc.rn = 1
            {%- endif %}
            )
    {%- endif %}

    )

SELECT * FROM records_to_insert

{%- endmacro -%}

macro.datavault4dbt.synapse__ref_sat_v1.macro_sql:
{%- macro synapse__ref_sat_v1(ref_sat_v0, ref_keys, hashdiff, src_ldts, src_rsrc, ledts_alias, add_is_current_flag) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set is_current_col_alias = var('datavault4dbt.is_current_col_alias', 'IS_CURRENT') -%}

{%- set source_relation = ref(ref_sat_v0) -%}

{%- set ref_keys = datavault4dbt.expand_column_list(columns=[ref_keys]) -%}

{%- set all_columns = datavault4dbt.source_columns(source_relation=source_relation) -%}
{%- set exclude = ref_keys + [hashdiff, src_ldts, src_rsrc] -%}

{%- set source_columns_to_select = datavault4dbt.process_columns_to_select(all_columns, exclude) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Calculate ledts based on the ldts of the earlier record. #}
end_dated_source AS (

    SELECT
        {% for ref_key in ref_keys %}
        {{ref_key}},
        {% endfor %}
        {{ hashdiff }},
        {{ src_rsrc }},
        {{ src_ldts }},
        COALESCE(LEAD(DATEADD(ns, -100, {{ src_ldts }})) OVER (PARTITION BY {%- for ref_key in ref_keys %} {{ref_key}} {%- if not loop.last %}, {% endif %}{% endfor %} ORDER BY {{ src_ldts }}),{{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}) AS {{ ledts_alias }},
        {{ datavault4dbt.print_list(source_columns_to_select) }}
    FROM {{ source_relation }}

)

SELECT
    {% for ref_key in ref_keys %}
    {{ref_key}},
    {% endfor %}
    {{ hashdiff }},
    {{ src_rsrc }},
    {{ src_ldts }},
    {{ ledts_alias }},
    {%- if add_is_current_flag %}
        CASE WHEN {{ ledts_alias }} = {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
        THEN 1
        ELSE 0
        END AS {{ is_current_col_alias }},
    {% endif -%}
    {{ datavault4dbt.print_list(source_columns_to_select) }}
FROM end_dated_source

{%- endmacro -%}

macro.datavault4dbt.synapse__ref_table.macro_sql:
{%- macro synapse__ref_table(ref_hub, ref_satellites, src_ldts, src_rsrc, historized, snapshot_trigger_column='is_active', snapshot_relation=none) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ref_hub_relation = ref(ref_hub|string) -%}

{%- set is_current_col_alias = var('datavault4dbt.is_current_col_alias', 'IS_CURRENT') -%}
{%- set ledts_alias = var('datavault4dbt.ledts_alias', 'ledts') -%}
{%- set sdts_alias = var('datavault4dbt.sdts_alias', 'sdts') -%}

{%- set include_business_objects_before_appearance = var('datavault4dbt.include_business_objects_before_appearance', 'false') -%}

{{ log('ref_hub_relation: ' ~ ref_hub_relation, false) }}
{%- set hub_columns = datavault4dbt.source_columns(ref_hub_relation) -%}
{{ log('hub_columns: ' ~ hub_columns, false) }}
{%- set hub_columns_to_exclude = [src_ldts, src_rsrc] -%}
{%- set ref_key_cols = datavault4dbt.process_columns_to_select(columns_list=hub_columns, exclude_columns_list=hub_columns_to_exclude )%}
{{ log('ref_key_cols: ' ~ ref_key_cols, false) }}
{%- set sat_columns_to_exclude = [src_ldts, src_rsrc, ledts_alias, is_current_col_alias] + ref_key_cols -%}
{{ log('sat_columns_to_exclude: '~ sat_columns_to_exclude, false) }}

{%- set ref_satellites_dict = {} -%}

{%- if not datavault4dbt.is_list(ref_satellites) and not ref_satellites is mapping -%}
    {%- set ref_satellites = [ref_satellites] -%}
{%- endif -%}

{%- if datavault4dbt.is_list(ref_satellites) -%}
    {%- for ref_satellite in ref_satellites -%}
        {%- do ref_satellites_dict.update({ref_satellite:{}}) -%}
    {%- endfor -%}
{%- else -%}
    {%- set ref_satellites_dict = ref_satellites -%}
{%- endif -%}


WITH 

dates AS (

{% if historized in ['full', 'latest'] -%}

    {%- set date_column = src_ldts -%}


    {{ log('ref_satellites: '~ ref_satellites, false) -}}

    {% if historized == 'full' -%}
    SELECT distinct {{ date_column }} FROM (
    {%- elif historized == 'latest' -%}
    SELECT MAX({{ date_column }}) as {{ date_column }} FROM (
    {%- endif -%}

    SELECT distinct 
        {{ src_ldts }}
    FROM {{ ref_hub_relation }}
    WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    UNION

    {% for satellite in ref_satellites_dict.keys() -%}
    SELECT distinct 
        {{ src_ldts }}
    FROM {{ ref(satellite|string) }}
    WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    {% if not loop.last -%} UNION {% endif %}
    {%- endfor %}
    ) sub


{% elif snapshot_relation is not none %}

    {%- set date_column = sdts_alias -%}

    SELECT 
        {{ sdts_alias }}
    FROM {{ ref(snapshot_relation) }}
    WHERE {{ snapshot_trigger_column }} = 1

{%- endif %}

{%- if is_incremental() -%}
    WHERE {{ date_column }} > (
        SELECT 
            COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}) 
        FROM {{ this }}
    )
{%- endif -%}

),

ref_table AS (

    SELECT
    {{ datavault4dbt.print_list(list_to_print=ref_key_cols, indent=2, src_alias='h') }},
        ld.{{ date_column }},
        h.{{ src_rsrc }},

    {%- for satellite in ref_satellites_dict.keys() %}

    {%- set sat_alias = 's_' + loop.index|string -%}
    {%- set sat_columns_pre = [] -%}
        
        {%- if ref_satellites_dict[satellite] is mapping and 'include' in ref_satellites_dict[satellite].keys() -%}
            {%- set sat_columns_pre = ref_satellites_dict[satellite]['include'] -%}
        {%- elif ref_satellites_dict[satellite] is mapping and 'exclude' in ref_satellites_dict[satellite].keys() -%}
            {%- set all_sat_columns = datavault4dbt.source_columns(ref(satellite)) -%}
            {%- set sat_columns_pre = datavault4dbt.process_columns_to_select(all_sat_columns, ref_satellites_dict[satellite]['exclude']) -%}
        {%- elif datavault4dbt.is_list(ref_satellites_dict[satellite]) -%}
            {%- set sat_columns_pre = ref_satellites_dict[satellite] -%}
        {%- else -%}
            {%- set all_sat_columns = datavault4dbt.source_columns(ref(satellite)) -%}
            {%- set sat_columns_pre = datavault4dbt.process_columns_to_select(all_sat_columns, sat_columns_to_exclude) -%}
        {%- endif -%}

    {%- set sat_columns = datavault4dbt.process_columns_to_select(sat_columns_pre, sat_columns_to_exclude) -%}
    
    {{- log('sat_columns: '~ sat_columns, false) -}}

    {{ datavault4dbt.print_list(list_to_print=sat_columns, indent=2, src_alias=sat_alias) }}
    {%- if not loop.last -%} ,
    {% endif -%}

    {% endfor %} 

    FROM {{ ref(ref_hub) }} h
    
    FULL OUTER JOIN dates ld
        ON 1 = 1  

    {% for satellite in ref_satellites_dict.keys() %}

        {%- set sat_alias = 's_' + loop.index|string -%}

    LEFT JOIN {{ ref(satellite) }} {{ sat_alias }}
        ON {{ datavault4dbt.multikey(columns=ref_key_cols, prefix=['h', sat_alias], condition='=') }}
        AND  ld.{{ date_column }} BETWEEN {{ sat_alias }}.{{ src_ldts }} AND {{ sat_alias }}.{{ ledts_alias }}
    
    {% endfor %}
    
    {% if include_business_objects_before_appearance == 'false' -%}
    WHERE h.{{ src_ldts }} <= ld.{{ date_column }}
    {% endif %}

) 

SELECT * FROM ref_table

{%- endmacro -%}

macro.datavault4dbt.synapse__sat_v0.macro_sql:
{%- macro synapse__sat_v0(parent_hashkey, src_hashdiff, src_payload, src_ldts, src_rsrc, source_model, disable_hwm, source_is_single_batch, additional_columns) -%}

{%- set beginning_of_all_times = datavault4dbt.beginning_of_all_times() -%}
{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set ns=namespace(src_hashdiff="", hdiff_alias="") %}

{%- if  src_hashdiff is mapping and src_hashdiff is not none -%}
    {% set ns.src_hashdiff = src_hashdiff["source_column"] %}
    {% set ns.hdiff_alias = src_hashdiff["alias"] %}
{% else %}
    {% set ns.src_hashdiff = src_hashdiff %}
    {% set ns.hdiff_alias = src_hashdiff  %}
{%- endif -%}

{# Select the additional_columns and put them in an array. If additional_colums none, then empty array #}
{%- set additional_columns = additional_columns | default([],true) -%}
{%- set additional_columns = [additional_columns] if additional_columns is string else additional_columns -%}

{%- set source_cols = datavault4dbt.expand_column_list(columns=[src_rsrc, src_ldts, src_payload, additional_columns]) -%}

{%- set source_relation = ref(source_model) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Selecting all source data, that is newer than latest data in sat if incremental #}
source_data AS (

    SELECT
        {{ parent_hashkey }},
        {{ ns.src_hashdiff }} as {{ ns.hdiff_alias }},
        {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ source_relation }}

    {%- if is_incremental() and not disable_hwm %}
    WHERE {{ src_ldts }} > (
        SELECT
            COALESCE(MAX({{ src_ldts }}), {{ datavault4dbt.string_to_timestamp(timestamp_format, beginning_of_all_times) }}) FROM {{ this }}
        WHERE {{ src_ldts }} != {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
    )
    {%- endif %}

    {%- set source_cte = 'source_data' -%}

),

{# Get the latest record for each parent hashkey in existing sat, if incremental. #}
{%- if is_incremental() %}
distinct_incoming_hashkeys AS (

    SELECT DISTINCT
        {{ parent_hashkey }}
    FROM source_data

),

latest_entries_in_sat_prep AS (

    SELECT
        tgt.{{ parent_hashkey }},
        tgt.{{ ns.hdiff_alias }},
        ROW_NUMBER() OVER(PARTITION BY tgt.{{ parent_hashkey|lower }} ORDER BY tgt.{{ src_ldts }} DESC) as rn
    FROM {{ this }} tgt
    INNER JOIN distinct_incoming_hashkeys src
        ON tgt.{{ parent_hashkey }} = src.{{ parent_hashkey }}
     WHERE 1=1
        
    {{ datavault4dbt.filter_latest_entries_in_sat() }}

),

latest_entries_in_sat AS (

    SELECT
        {{ parent_hashkey }},
        {{ ns.hdiff_alias }}
    FROM 
        latest_entries_in_sat_prep
    WHERE rn = 1  
),
{%- endif %}

{%- if not source_is_single_batch %}
{#
    Deduplicate source by comparing each hashdiff to the hashdiff of the previous record, for each hashkey.
    Additionally adding a row number based on that order, if incremental.
#}
deduplicated_numbered_source_prep AS (

    SELECT
    {{ parent_hashkey }},
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    , LAG({{ ns.hdiff_alias }}) OVER(PARTITION BY {{ parent_hashkey|lower }} ORDER BY {{ src_ldts }}) as prev_hashdiff
    FROM source_data

),

deduplicated_numbered_source AS (

    SELECT
    {{ parent_hashkey }},
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    {% if is_incremental() -%}
    , ROW_NUMBER() OVER(PARTITION BY {{ parent_hashkey }} ORDER BY {{ src_ldts }}) as rn
    {%- endif %}
    FROM deduplicated_numbered_source_prep
    WHERE 1=1
        AND {{ ns.hdiff_alias }} <> prev_hashdiff OR prev_hashdiff IS NULL

    {%- set source_cte = 'deduplicated_numbered_source' -%}

),

{% endif -%}

{#
    Select all records from the previous CTE. If incremental, compare the oldest incoming entry to
    the existing records in the satellite.
#}
records_to_insert AS (

    SELECT
    {{ parent_hashkey }},
    {{ ns.hdiff_alias }},
    {{ datavault4dbt.print_list(source_cols) }}
    FROM {{ source_cte }} sc
    {%- if is_incremental() %}
    WHERE NOT EXISTS (
        SELECT 1
        FROM latest_entries_in_sat
        WHERE {{ datavault4dbt.multikey(parent_hashkey, prefix=['latest_entries_in_sat', 'sc'], condition='=') }}
            AND {{ datavault4dbt.multikey(ns.hdiff_alias, prefix=['latest_entries_in_sat', 'sc'], condition='=') }}
            {%- if not source_is_single_batch %}
            AND sc.rn = 1
            {%- endif %}
    )
    {%- endif %}

    )

SELECT * FROM records_to_insert

{%- endmacro -%}

macro.datavault4dbt.synapse__sat_v1.macro_sql:
{%- macro synapse__sat_v1(sat_v0, hashkey, hashdiff, src_ldts, src_rsrc, ledts_alias, add_is_current_flag, include_payload) -%}

{%- set end_of_all_times = datavault4dbt.end_of_all_times() -%}
{%- set timestamp_format = datavault4dbt.timestamp_format() -%}

{%- set is_current_col_alias = var('datavault4dbt.is_current_col_alias', 'IS_CURRENT') -%}

{%- set source_relation = ref(sat_v0) -%}

{%- set all_columns = datavault4dbt.source_columns(source_relation=source_relation) -%}
{%- set exclude = [hashkey, hashdiff, src_ldts, src_rsrc] -%}

{%- set source_columns_to_select = datavault4dbt.process_columns_to_select(all_columns, exclude) -%}

{{ datavault4dbt.prepend_generated_by() }}

WITH

{# Calculate ledts based on the ldts of the earlier record. #}
end_dated_source AS (

    SELECT
        {{ hashkey }},
        {{ hashdiff }},
        {{ src_rsrc }},
        {{ src_ldts }},
        COALESCE(LEAD(DATEADD(ns, -100, {{ src_ldts }})) OVER (PARTITION BY {{ hashkey }} ORDER BY {{ src_ldts }}),{{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}) AS {{ ledts_alias }}
       {%- if source_columns_to_select | length >= 1 -%} , {% endif -%}
        {{ datavault4dbt.print_list(source_columns_to_select) }}
    FROM {{ source_relation }}

)

SELECT
    {{ hashkey }},
    {{ hashdiff }},
    {{ src_rsrc }},
    {{ src_ldts }},
    {{ ledts_alias }}
    {%- if source_columns_to_select | length >= 1 or add_is_current_flag -%} , {% endif -%}
    {%- if add_is_current_flag %}
        CASE WHEN {{ ledts_alias }} = {{ datavault4dbt.string_to_timestamp(timestamp_format, end_of_all_times) }}
          THEN 1
          ELSE 0
        END AS {{ is_current_col_alias }}
        {%- if source_columns_to_select | length >= 1 -%} , {% endif -%}
    {% endif -%}
    {{ datavault4dbt.print_list(source_columns_to_select) }}
FROM end_dated_source

{%- endmacro -%}
